  async getVideos(search?: string, categoryId?: number, userId?: number): Promise<VideoWithCategory[]> {
    // Get basic video data with primary category info
    let baseQuery = db
      .select({
        id: videos.id,
        title: videos.title,
        description: videos.description,
        youtubeId: videos.youtubeId,
        thumbnailUrl: videos.thumbnailUrl,
        duration: videos.duration,
        categoryId: videos.categoryId,
        tags: videos.tags,
        views: videos.views,
        isPublic: videos.isPublic,
        createdAt: videos.createdAt,
        updatedAt: videos.updatedAt,
        category: categories,
      })
      .from(videos)
      .leftJoin(categories, eq(videos.categoryId, categories.id));

    const conditions = [];

    if (search) {
      conditions.push(
        or(
          ilike(videos.title, `%${search}%`),
          ilike(videos.description, `%${search}%`),
          sql`${videos.tags}::text ILIKE ${'%' + search + '%'}`
        )
      );
    }

    if (categoryId) {
      // Filter by videos that have this category either as primary or secondary
      const videosInCategory = await db
        .select({ videoId: videoCategories.videoId })
        .from(videoCategories)
        .where(eq(videoCategories.categoryId, categoryId));

      if (videosInCategory.length > 0) {
        const videoIds = videosInCategory.map(v => v.videoId);
        conditions.push(inArray(videos.id, videoIds));
      } else {
        // No videos in this category
        conditions.push(sql`FALSE`);
      }
    }

    // Add category access control for non-admin users
    if (userId) {
      const user = await this.getUser(userId);
      const publicUser = await this.getPublicUser(userId);

      if (publicUser) {
        // Public users can only access "Other" category videos
        const otherCategory = await db
          .select({ id: categories.id })
          .from(categories)
          .where(eq(categories.slug, 'other'))
          .limit(1);

        if (otherCategory.length > 0) {
          const otherCategoryVideos = await db
            .select({ videoId: videoCategories.videoId })
            .from(videoCategories)
            .where(eq(videoCategories.categoryId, otherCategory[0].id));

          if (otherCategoryVideos.length > 0) {
            const otherVideoIds = otherCategoryVideos.map(v => v.videoId);
            conditions.push(inArray(videos.id, otherVideoIds));
          } else {
            conditions.push(sql`FALSE`);
          }
        } else {
          // If no "Other" category exists, show no videos
          conditions.push(sql`FALSE`);
        }
      } else if (user && !user.isAdmin) {
        // Regular admin users - get assigned categories
        const userCategories = await db
          .select({ categoryId: userCategoryAccess.categoryId })
          .from(userCategoryAccess)
          .where(eq(userCategoryAccess.userId, userId));

        // Get "Other" category ID
        const otherCategory = await db
          .select({ id: categories.id })
          .from(categories)
          .where(eq(categories.slug, 'other'))
          .limit(1);

        const allowedCategoryIds = userCategories.map(row => row.categoryId);
        if (otherCategory.length > 0) {
          allowedCategoryIds.push(otherCategory[0].id);
        }

        // Only show videos from allowed categories (including secondary categories)
        if (allowedCategoryIds.length > 0) {
          const allowedVideos = await db
            .select({ videoId: videoCategories.videoId })
            .from(videoCategories)
            .where(inArray(videoCategories.categoryId, allowedCategoryIds));

          if (allowedVideos.length > 0) {
            const allowedVideoIds = allowedVideos.map(v => v.videoId);
            conditions.push(inArray(videos.id, allowedVideoIds));
          } else {
            conditions.push(sql`FALSE`);
          }
        } else {
          // If no categories assigned, only show "Other" category videos
          if (otherCategory.length > 0) {
            const otherCategoryVideos = await db
              .select({ videoId: videoCategories.videoId })
              .from(videoCategories)
              .where(eq(videoCategories.categoryId, otherCategory[0].id));

            if (otherCategoryVideos.length > 0) {
              const otherVideoIds = otherCategoryVideos.map(v => v.videoId);
              conditions.push(inArray(videos.id, otherVideoIds));
            } else {
              conditions.push(sql`FALSE`);
            }
          } else {
            // If no "Other" category exists, show no videos
            conditions.push(sql`FALSE`);
          }
        }
      }
    }

    if (conditions.length > 0) {
      baseQuery = baseQuery.where(and(...conditions)) as any;
    }

    const baseResult = await baseQuery.orderBy(desc(videos.createdAt));

    // Enhance videos with all categories they belong to
    const enhancedVideos = await Promise.all(
      baseResult.map(async (video) => {
        const allCategories = await this.getVideoCategories(video.id);

        return {
          ...video,
          categories: allCategories,
          viewCount: 0,
          isCompleted: false,
          averageRating: 4.5,
          totalRatings: 10,
          userRating: undefined,
          commentsCount: 3,
        };
      })
    );

    return enhancedVideos;
  }

  async getVideo(id: number): Promise<VideoWithCategory | undefined> {
    const [result] = await db
      .select({
        id: videos.id,
        title: videos.title,
        description: videos.description,
        youtubeId: videos.youtubeId,
        thumbnailUrl: videos.thumbnailUrl,
        duration: videos.duration,
        categoryId: videos.categoryId,
        tags: videos.tags,
        views: videos.views,
        isPublic: videos.isPublic,
        createdAt: videos.createdAt,
        updatedAt: videos.updatedAt,
        category: categories,
        viewCount: sql<number>`COUNT(${videoViews.id})::int`.as('viewCount'),
      })
      .from(videos)
      .leftJoin(categories, eq(videos.categoryId, categories.id))
      .leftJoin(videoViews, eq(videos.id, videoViews.videoId))
      .where(eq(videos.id, id))
      .groupBy(videos.id, categories.id);

    if (!result) return undefined;

    // Get all categories for this video
    const allCategories = await this.getVideoCategories(id);

    return {
      ...result,
      categories: allCategories,
      viewCount: result.viewCount || 0,
    };
  }

