  async getAdminStats(): Promise<AdminStats> {
    const [videoStats] = await db
      .select({
        totalVideos: sql<number>`COUNT(*)::int`,
      })
      .from(videos);

    const [userStats] = await db
      .select({
        totalUsers: sql<number>`COUNT(*)::int`,
      })
      .from(users)
      .where(eq(users.isVerified, true));

    const [viewStats] = await db
      .select({
        totalViews: sql<number>`COUNT(*)::int`,
      })
      .from(videoViews);

    // Get active user counts
    const now = new Date();
    const dayAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000);
    const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
    const monthAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);

    // Since watchHistory might be empty initially, provide default values
    const dailyActiveUsers = [{ count: 0 }];
    const weeklyActiveUsers = [{ count: 0 }];
    const monthlyActiveUsers = [{ count: 0 }];
    const popularDevices: Array<{ deviceInfo: string; count: number }> = [];

    const recentSignups = await db
      .select({ count: sql<number>`COUNT(*)::int` })
      .from(users)
      .where(sql`${users.createdAt} >= ${monthAgo}`);

    return {
      totalVideos: videoStats?.totalVideos || 0,
      totalUsers: userStats?.totalUsers || 0,
      totalViews: viewStats?.totalViews || 0,
      totalWatchTime: "0h", 
      dailyActiveUsers: dailyActiveUsers[0]?.count || 0,
      weeklyActiveUsers: weeklyActiveUsers[0]?.count || 0,
      monthlyActiveUsers: monthlyActiveUsers[0]?.count || 0,
      popularDevices: popularDevices,
      recentSignups: recentSignups[0]?.count || 0,
    };
  }

  // Video completion tracking methods
  async markVideoComplete(userId: number, videoId: number, watchTime: number): Promise<VideoCompletion> {
    const [completion] = await db
      .insert(videoCompletions)
      .values({ userId, videoId, watchTime })
      .onConflictDoUpdate({
        target: [videoCompletions.userId, videoCompletions.videoId],
        set: {
          completedAt: sql`NOW()`,
          watchTime: watchTime,
        },
      })
      .returning();
    return completion;
  }

  async markVideoIncomplete(userId: number, videoId: number): Promise<void> {
    await db
      .delete(videoCompletions)
      .where(and(eq(videoCompletions.userId, userId), eq(videoCompletions.videoId, videoId)));
  }

  async getUserVideoCompletions(userId: number): Promise<VideoCompletion[]> {
    return await db
      .select({
        id: videoCompletions.id,
        userId: videoCompletions.userId,
        videoId: videoCompletions.videoId,
        completedAt: videoCompletions.completedAt,
        watchTime: videoCompletions.watchTime,
        video: {
          id: videos.id,
          title: videos.title,
          description: videos.description,
          thumbnailUrl: videos.thumbnailUrl,
          youtubeId: videos.youtubeId,
          duration: videos.duration,
          categoryId: videos.categoryId,
          isPublic: videos.isPublic,
          createdAt: videos.createdAt,
        },
      })
      .from(videoCompletions)
      .innerJoin(videos, eq(videoCompletions.videoId, videos.id))
      .where(eq(videoCompletions.userId, userId))
      .orderBy(desc(videoCompletions.completedAt));
  }

  async getCategoryProgress(userId: number, categoryId: number): Promise<{ completed: number; total: number }> {
    // Count total videos in this category through the junction table
    const totalVideos = await db
      .select({ count: sql<number>`COUNT(DISTINCT ${videos.id})::int` })
      .from(videos)
      .innerJoin(videoCategories, eq(videos.id, videoCategories.videoId))
      .where(eq(videoCategories.categoryId, categoryId));

    // Count completed videos in this category through the junction table  
    const completedVideos = await db
      .select({ count: sql<number>`COUNT(DISTINCT ${videos.id})::int` })
      .from(videos)
      .innerJoin(videoCategories, eq(videos.id, videoCategories.videoId))
      .innerJoin(videoCompletions, eq(videos.id, videoCompletions.videoId))
      .where(and(
        eq(videoCategories.categoryId, categoryId), 
        eq(videoCompletions.userId, userId)
      ));

    return {
      total: totalVideos[0]?.count || 0,
      completed: completedVideos[0]?.count || 0,
    };
  }

  // Video bookmark management methods
  async bookmarkVideo(userId: number, videoId: number): Promise<VideoBookmark> {
    const [bookmark] = await db
      .insert(videoBookmarks)
      .values({ userId, videoId })
      .onConflictDoNothing()
      .returning();
    return bookmark;
  }

  async removeBookmark(userId: number, videoId: number): Promise<void> {
    await db
      .delete(videoBookmarks)
      .where(and(eq(videoBookmarks.userId, userId), eq(videoBookmarks.videoId, videoId)));
  }

  async getUserBookmarks(userId: number): Promise<VideoBookmark[]> {
    return await db
      .select({
        id: videoBookmarks.id,
        userId: videoBookmarks.userId,
        videoId: videoBookmarks.videoId,
        bookmarkedAt: videoBookmarks.bookmarkedAt,
        video: {
          id: videos.id,
          title: videos.title,
          description: videos.description,
          thumbnailUrl: videos.thumbnailUrl,
          youtubeId: videos.youtubeId,
          duration: videos.duration,
          categoryId: videos.categoryId,
          isPublic: videos.isPublic,
          createdAt: videos.createdAt,
          category: {
            id: categories.id,
            name: categories.name,
            slug: categories.slug,
          },
        },
      })
      .from(videoBookmarks)
      .innerJoin(videos, eq(videoBookmarks.videoId, videos.id))
      .leftJoin(categories, eq(videos.categoryId, categories.id))
      .where(eq(videoBookmarks.userId, userId))
      .orderBy(desc(videoBookmarks.bookmarkedAt));
  }

  // Watch history tracking methods
  async recordWatchHistory(watchData: InsertWatchHistory): Promise<WatchHistory> {
    const [history] = await db
      .insert(watchHistory)
      .values(watchData)
      .returning();
    return history;
  }

  async getUserWatchHistory(userId: number, limit: number = 50): Promise<WatchHistory[]> {
    return await db
      .select({
        id: watchHistory.id,
        userId: watchHistory.userId,
        videoId: watchHistory.videoId,
        watchDuration: watchHistory.watchDuration,
        progressPercentage: watchHistory.progressPercentage,
        deviceInfo: watchHistory.deviceInfo,
        ipAddress: watchHistory.ipAddress,
        watchedAt: watchHistory.watchedAt,
        video: {
          id: videos.id,
          title: videos.title,
          description: videos.description,
          thumbnailUrl: videos.thumbnailUrl,
          youtubeId: videos.youtubeId,
          duration: videos.duration,
          categoryId: videos.categoryId,
          isPublic: videos.isPublic,
          createdAt: videos.createdAt,
          category: {
            id: categories.id,
            name: categories.name,
            slug: categories.slug,
            description: categories.description,
            coverImage: categories.coverImage,
            createdAt: categories.createdAt,
          },
        },
      })
      .from(watchHistory)
      .innerJoin(videos, eq(watchHistory.videoId, videos.id))
      .leftJoin(categories, eq(videos.categoryId, categories.id))
      .where(eq(watchHistory.userId, userId))
      .orderBy(desc(watchHistory.watchedAt))
      .limit(limit) as any;
  }

  // User session management methods
  async startUserSession(sessionData: InsertUserSession): Promise<UserSession> {
    const [session] = await db
      .insert(userSessions)
      .values(sessionData)
      .returning();
    return session;
  }

  async endUserSession(sessionId: number, totalWatchTime: number): Promise<void> {
    await db
      .update(userSessions)
      .set({ 
        sessionEnd: new Date(),
        totalWatchTime 
      })
      .where(eq(userSessions.id, sessionId));
  }

  async getUserSessions(userId: number): Promise<UserSession[]> {
    return await db
      .select()
      .from(userSessions)
      .where(eq(userSessions.userId, userId))
      .orderBy(desc(userSessions.sessionStart));
  }

  // User learning analytics method
  async getUserLearningStats(userId: number): Promise<UserLearningStats> {
    // Get total videos watched (unique videos from watch history)
    const uniqueVideosWatched = await db
      .select({ count: sql<number>`COUNT(DISTINCT ${watchHistory.videoId})::int` })
      .from(watchHistory)
      .where(eq(watchHistory.userId, userId));

    // Get total watch time
    const totalWatchTimeQuery = await db
      .select({ total: sql<number>`COALESCE(SUM(${watchHistory.watchDuration}), 0)::int` })
      .from(watchHistory)
      .where(eq(watchHistory.userId, userId));

    // Get completed videos count
    const completedVideosCount = await db
      .select({ count: sql<number>`COUNT(*)::int` })
      .from(videoCompletions)
      .where(eq(videoCompletions.userId, userId));

    // Get bookmarked videos count
    const bookmarkedVideosCount = await db
      .select({ count: sql<number>`COUNT(*)::int` })
      .from(videoBookmarks)
      .where(eq(videoBookmarks.userId, userId));

    // Get last active date
    const lastActiveQuery = await db
      .select({ lastActive: sql<Date>`MAX(${watchHistory.watchedAt})` })
      .from(watchHistory)
      .where(eq(watchHistory.userId, userId));

    // Get category progress
    const categoryProgressQuery = await db
      .select({
        categoryId: videos.categoryId,
        categoryName: categories.name,
        totalVideos: sql<number>`COUNT(DISTINCT ${videos.id})::int`,
        completedVideos: sql<number>`COUNT(DISTINCT ${videoCompletions.videoId})::int`,
      })
      .from(videos)
      .leftJoin(categories, eq(videos.categoryId, categories.id))
      .leftJoin(videoCompletions, and(
        eq(videos.id, videoCompletions.videoId),
        eq(videoCompletions.userId, userId)
      ))
      .where(isNotNull(videos.categoryId))
      .groupBy(videos.categoryId, categories.name);

    return {
      totalVideosWatched: uniqueVideosWatched[0]?.count || 0,
      totalWatchTime: totalWatchTimeQuery[0]?.total || 0,
      completedVideos: completedVideosCount[0]?.count || 0,
      bookmarkedVideos: bookmarkedVideosCount[0]?.count || 0,
      currentStreak: 0, // TODO: Implement streak calculation
      lastActiveDate: lastActiveQuery[0]?.lastActive || null,
      preferredDevice: null, // TODO: Implement based on session data
      categoriesProgress: categoryProgressQuery.map(row => ({
        categoryId: row.categoryId!,
        categoryName: row.categoryName || 'Unknown',
        completed: row.completedVideos,
        total: row.totalVideos,
        percentage: row.totalVideos > 0 ? Math.round((row.completedVideos / row.totalVideos) * 100) : 0,
      })),
    };
  }
  async rateVideo(userId: number, videoId: number, rating: number, review?: string): Promise<VideoRating> {
    const [existingRating] = await db
      .select()
      .from(videoRatings)
      .where(and(eq(videoRatings.userId, userId), eq(videoRatings.videoId, videoId)));

    if (existingRating) {
      const [updatedRating] = await db
        .update(videoRatings)
        .set({ rating, review, updatedAt: new Date() })
        .where(and(eq(videoRatings.userId, userId), eq(videoRatings.videoId, videoId)))
        .returning();
      return updatedRating;
    } else {
      const [newRating] = await db
        .insert(videoRatings)
        .values({ userId, videoId, rating, review })
        .returning();
      return newRating;
    }
  }

  async getUserVideoRating(userId: number, videoId: number): Promise<VideoRating | undefined> {
    const [rating] = await db
      .select()
      .from(videoRatings)
      .where(and(eq(videoRatings.userId, userId), eq(videoRatings.videoId, videoId)));
    return rating || undefined;
  }

  async getVideoComments(videoId: number): Promise<any[]> {
    const comments = await db
      .select({
        id: videoComments.id,
        content: videoComments.content,
        createdAt: videoComments.createdAt,
        parentId: videoComments.parentId,
        user: {
          id: users.id,
          username: users.username,
          fullName: users.fullName,
        },
      })
      .from(videoComments)
      .innerJoin(users, eq(videoComments.userId, users.id))
      .where(eq(videoComments.videoId, videoId))
      .orderBy(desc(videoComments.createdAt));

    // Organize comments with replies
    const commentMap = new Map();
    const rootComments = [];

    for (const comment of comments) {
      comment.replies = [];
      commentMap.set(comment.id, comment);

      if (comment.parentId) {
        const parent = commentMap.get(comment.parentId);
        if (parent) {
          parent.replies.push(comment);
        }
      } else {
        rootComments.push(comment);
      }
    }

    return rootComments;
  }

  async createVideoComment(userId: number, videoId: number, content: string, parentId?: number): Promise<VideoComment> {
    const [comment] = await db
      .insert(videoComments)
      .values({ userId, videoId, content, parentId })
      .returning();
    return comment;
  }

  // Broadcast notifications management
  async createBroadcastNotification(notification: InsertBroadcastNotification): Promise<BroadcastNotification> {
    const [createdNotification] = await db.insert(broadcastNotifications).values(notification).returning();
    return createdNotification;
  }

  async getBroadcastNotifications(userId?: number): Promise<BroadcastNotification[]> {
    let query = db.select().from(broadcastNotifications);

    if (userId) {
      // Get notifications for specific user based on target audience
      query = query.where(
        or(
          eq(broadcastNotifications.targetAudience, 'all'),
          eq(broadcastNotifications.targetAudience, 'students'),
          and(
            eq(broadcastNotifications.targetAudience, 'category_specific'),
            isNotNull(broadcastNotifications.categoryId)
          )
        )
      );
    }

    return await query.orderBy(desc(broadcastNotifications.createdAt));
  }

  async updateBroadcastNotification(id: number, notification: Partial<InsertBroadcastNotification>): Promise<BroadcastNotification> {
    const [updated] = await db.update(broadcastNotifications)
      .set({ ...notification, updatedAt: new Date() })
      .where(eq(broadcastNotifications.id, id))
      .returning();
    return updated;
  }

  async deleteBroadcastNotification(id: number): Promise<void> {
    await db.delete(broadcastNotifications).where(eq(broadcastNotifications.id, id));
  }

  async getUserNotifications(userId: number): Promise<any[]> {
    const notifications = await db
      .select()
      .from(broadcastNotifications)
      .where(
        or(
          eq(broadcastNotifications.targetAudience, 'all'),
          eq(broadcastNotifications.targetAudience, 'students')
        )
      )
      .orderBy(desc(broadcastNotifications.createdAt));

    // Get read status for each notification
    const notificationsWithStatus = await Promise.all(
      notifications.map(async (notification) => {
        const [status] = await db
          .select()
          .from(userNotificationStatus)
          .where(
            and(
              eq(userNotificationStatus.userId, userId),
              eq(userNotificationStatus.notificationId, notification.id)
            )
          );

        return {
          ...notification,
          isRead: status?.isRead || false,
        };
      })
    );

    return notificationsWithStatus;
  }

  async markAllNotificationsAsRead(userId: number): Promise<void> {
    const unreadNotifications = await db
      .select({ id: broadcastNotifications.id })
      .from(broadcastNotifications)
      .leftJoin(
        userNotificationStatus,
        and(
          eq(userNotificationStatus.notificationId, broadcastNotifications.id),
          eq(userNotificationStatus.userId, userId)
        )
      )
      .where(
        and(
          or(
            eq(broadcastNotifications.targetAudience, 'all'),
            eq(broadcastNotifications.targetAudience, 'students')
          ),
          or(
            sql`${userNotificationStatus.isRead} IS NULL`,
            eq(userNotificationStatus.isRead, false)
          )
        )
      );

    for (const notification of unreadNotifications) {
      await this.markNotificationAsRead(userId, notification.id);
    }
  }

  async markNotificationAsRead(userId: number, notificationId: number): Promise<void> {
    await db.insert(userNotificationStatus).values({
      userId,
      notificationId,
      isRead: true,
      readAt: new Date(),
    }).onConflictDoUpdate({
      target: [userNotificationStatus.userId, userNotificationStatus.notificationId],
      set: {
        isRead: true,
        readAt: new Date(),
      },
    });
  }

  async markNotificationAsClicked(userId: number, notificationId: number): Promise<void> {
    await db.insert(userNotificationStatus).values({
      userId,
      notificationId,
      isClicked: true,
      clickedAt: new Date(),
    }).onConflictDoUpdate({
      target: [userNotificationStatus.userId, userNotificationStatus.notificationId],
      set: {
        isClicked: true,
        clickedAt: new Date(),
      },
    });
  }

  async getUserNotificationStatus(userId: number): Promise<UserNotificationStatus[]> {
    return await db.select().from(userNotificationStatus).where(eq(userNotificationStatus.userId, userId));
  }

  // Events management
  async createEvent(event: InsertEvent): Promise<Event> {
    const [createdEvent] = await db.insert(events).values(event).returning();
    return createdEvent;
  }

  async getEvents(isPublic?: boolean, status?: string): Promise<Event[]> {
    let query = db.select().from(events);

    if (isPublic !== undefined) {
      query = query.where(eq(events.isPublic, isPublic));
    }

    if (status) {
      query = query.where(eq(events.status, status));
    }

    return await query.orderBy(desc(events.startDate));
  }

  async getEvent(id: number): Promise<Event | undefined> {
    const [event] = await db.select().from(events).where(eq(events.id, id));
    return event || undefined;
  }

  async updateEvent(id: number, event: Partial<InsertEvent>): Promise<Event> {
    const [updated] = await db.update(events)
      .set({ ...event, updatedAt: new Date() })
      .where(eq(events.id, id))
      .returning();
    return updated;
  }

  async deleteEvent(id: number): Promise<void> {
    await db.delete(events).where(eq(events.id, id));
  }

  async registerForEvent(registration: InsertEventRegistration): Promise<EventRegistration> {
    const [createdRegistration] = await db.insert(eventRegistrations).values(registration).returning();

    // Update event participant count
    await db.update(events)
      .set({ 
        currentParticipants: sql`${events.currentParticipants} + 1`
      })
      .where(eq(events.id, registration.eventId));

    return createdRegistration;
  }

  async getEventRegistrations(eventId: number): Promise<EventRegistration[]> {
    return await db.select().from(eventRegistrations).where(eq(eventRegistrations.eventId, eventId));
  }

  async getUserEventRegistrations(userId: number): Promise<EventRegistration[]> {
    return await db.select().from(eventRegistrations).where(eq(eventRegistrations.userId, userId));
  }

  async updateEventRegistration(id: number, registration: Partial<InsertEventRegistration>): Promise<EventRegistration> {
    const [updated] = await db.update(eventRegistrations)
      .set(registration)
      .where(eq(eventRegistrations.id, id))
      .returning();
    return updated;
  }

  async cancelEventRegistration(id: number): Promise<void> {
    const [registration] = await db.select().from(eventRegistrations).where(eq(eventRegistrations.id, id));

    if (registration) {
      await db.update(eventRegistrations)
        .set({ 
          status: 'cancelled',
          cancelledAt: new Date()
        })
        .where(eq(eventRegistrations.id, id));

      // Update event participant count
      await db.update(events)
        .set({ 
          currentParticipants: sql`${events.currentParticipants} - 1`
        })
        .where(eq(events.id, registration.eventId));
    }
  }

  // Blog posts management
  async createBlogPost(post: InsertBlogPost): Promise<BlogPost> {
    const [createdPost] = await db.insert(blogPosts).values(post).returning();
    return createdPost;
  }

  async getBlogPosts(status?: string, isPublic?: boolean, isFeatured?: boolean): Promise<BlogPost[]> {
    let query = db.select().from(blogPosts);

    const conditions = [];

    if (status) {
      conditions.push(eq(blogPosts.status, status));
    }

    if (isPublic !== undefined) {
      conditions.push(eq(blogPosts.isPublic, isPublic));
    }

    if (isFeatured !== undefined) {
      conditions.push(eq(blogPosts.isFeatured, isFeatured));
    }

    if (conditions.length > 0) {
      query = query.where(and(...conditions));
    }

    return await query.orderBy(desc(blogPosts.createdAt));
  }

  async getBlogPost(id: number): Promise<BlogPost | undefined> {
    const [post] = await db.select().from(blogPosts).where(eq(blogPosts.id, id));
    return post || undefined;
  }

  async getBlogPostBySlug(slug: string): Promise<BlogPost | undefined> {
    const [post] = await db.select().from(blogPosts).where(eq(blogPosts.slug, slug));
    return post || undefined;
  }

  async updateBlogPost(id: number, post: Partial<InsertBlogPost>): Promise<BlogPost> {
    const [updated] = await db.update(blogPosts)
      .set({ ...post, updatedAt: new Date() })
      .where(eq(blogPosts.id, id))
      .returning();
    return updated;
  }

  async deleteBlogPost(id: number): Promise<void> {
    await db.delete(blogPosts).where(eq(blogPosts.id, id));
  }

  async incrementBlogPostViews(id: number): Promise<void> {
    await db.update(blogPosts)
      .set({ 
        viewCount: sql`${blogPosts.viewCount} + 1`
      })
      .where(eq(blogPosts.id, id));
  }

  // User profiles management
  async createUserProfile(profile: InsertUserProfile): Promise<UserProfile> {
    const [createdProfile] = await db.insert(userProfiles).values(profile).returning();
    return createdProfile;
  }

  async getUserProfile(userId: number): Promise<UserProfile | undefined> {
    const [profile] = await db.select().from(userProfiles).where(eq(userProfiles.userId, userId));
    return profile || undefined;
  }

  async getUserProfileByPublicUserId(publicUserId: number): Promise<UserProfile | undefined> {
    const [profile] = await db.select().from(userProfiles).where(eq(userProfiles.publicUserId, publicUserId));
    return profile || undefined;
  }

  async updateUserProfile(userId: number, profile: Partial<InsertUserProfile>): Promise<UserProfile> {
    const [updated] = await db.update(userProfiles)
      .set({ ...profile, updatedAt: new Date() })
      .where(eq(userProfiles.userId, userId))
      .returning();
    return updated;
  }

  async deleteUserProfile(userId: number): Promise<void> {
    await db.delete(userProfiles).where(eq(userProfiles.userId, userId));
  }

  async updateUserRole(id: number, isAdmin: boolean): Promise<User> {
    const [updatedUser] = await db.update(users)
      .set({ isAdmin, updatedAt: new Date() })
      .where(eq(users.id, id))
      .returning();
    return updatedUser;
  }
}

export const storage = new DatabaseStorage();

