server/services/youtube.ts.content:
export interface YouTubeVideoInfo {
  id: string;
  title: string;
  description: string;
  thumbnailUrl: string;
  duration: string;
}

export async function fetchYouTubeVideoInfo(url: string): Promise<YouTubeVideoInfo> {
  const videoId = extractVideoId(url);
  if (!videoId) {
    throw new Error('Invalid YouTube URL');
  }

  const apiKey = process.env.YOUTUBE_API_KEY;

  // If no API key, return fallback data
  if (!apiKey) {
    console.warn('YOUTUBE_API_KEY not configured - using basic video information. Set YOUTUBE_API_KEY for enhanced video metadata.');
    return {
      id: videoId,
      title: `YouTube Video ${videoId}`,
      description: 'Please add a custom description for this video.',
      thumbnailUrl: `https://img.youtube.com/vi/${videoId}/hqdefault.jpg`,
      duration: 'Unknown',
    };
  }

  try {
    const response = await fetch(
      `https://www.googleapis.com/youtube/v3/videos?id=${videoId}&key=${apiKey}&part=snippet,contentDetails`
    );

    if (!response.ok) {
      console.error('YouTube API request failed, using fallback data');
      return {
        id: videoId,
        title: `YouTube Video ${videoId}`,
        description: 'Please add a custom description for this video.',
        thumbnailUrl: `https://img.youtube.com/vi/${videoId}/hqdefault.jpg`,
        duration: 'Unknown',
      };
    }

    const data = await response.json();

    if (!data.items || data.items.length === 0) {
      throw new Error('Video not found');
    }

    const video = data.items[0];
    const snippet = video.snippet;
    const contentDetails = video.contentDetails;

    return {
      id: videoId,
      title: snippet.title,
      description: snippet.description,
      thumbnailUrl: snippet.thumbnails.high?.url || snippet.thumbnails.default?.url,
      duration: formatDuration(contentDetails.duration),
    };
  } catch (error) {
    console.error('YouTube API error, using fallback data:', error);
    return {
      id: videoId,
      title: `YouTube Video ${videoId}`,
      description: 'Please add a custom description for this video.',
      thumbnailUrl: `https://img.youtube.com/vi/${videoId}/hqdefault.jpg`,
      duration: 'Unknown',
    };
  }
}

function extractVideoId(url: string): string | null {
  const patterns = [
    /(?:youtube\.com\/watch\?v=|youtu\.be\/|youtube\.com\/embed\/)([^&\n?#]+)/,
    /youtube\.com\/watch\?.*v=([^&\n?#]+)/,
  ];

  for (const pattern of patterns) {
    const match = url.match(pattern);
    if (match) {
      return match[1];
    }
  }

  return null;
}

function formatDuration(duration: string): string {
  // Convert ISO 8601 duration (PT4M13S) to readable format (4:13)
  const match = duration.match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?/);
  if (!match) return '0:00';

  const hours = parseInt(match[1] || '0');
  const minutes = parseInt(match[2] || '0');
  const seconds = parseInt(match[3] || '0');

  if (hours > 0) {
    return `${hours}:${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
  }
  return `${minutes}:${seconds.toString().padStart(2, '0')}`;
}

server/utils/device-detection.ts.content:
import { Request } from 'express';

export interface DeviceInfo {
  deviceInfo: string;
  deviceType: string;
  browser: string;
  os: string;
  ipAddress: string;
  country?: string;
  city?: string;
  timezone?: string;
  screenResolution?: string;
}

export function parseUserAgent(userAgent: string): { browser: string; os: string; deviceType: string } {
  const ua = userAgent.toLowerCase();

  // Browser detection
  let browser = 'Unknown';
  if (ua.includes('chrome') && !ua.includes('edg')) {
    browser = 'Chrome';
  } else if (ua.includes('firefox')) {
    browser = 'Firefox';
  } else if (ua.includes('safari') && !ua.includes('chrome')) {
    browser = 'Safari';
  } else if (ua.includes('edg')) {
    browser = 'Edge';
  } else if (ua.includes('opera') || ua.includes('opr')) {
    browser = 'Opera';
  }

  // OS detection
  let os = 'Unknown';
  if (ua.includes('windows')) {
    os = 'Windows';
  } else if (ua.includes('mac os x') || ua.includes('macos')) {
    os = 'macOS';
  } else if (ua.includes('linux')) {
    os = 'Linux';
  } else if (ua.includes('android')) {
    os = 'Android';
  } else if (ua.includes('iphone') || ua.includes('ipad') || ua.includes('ipod')) {
    os = 'iOS';
  }

  // Device type detection
  let deviceType = 'desktop';
  if (ua.includes('mobile') || ua.includes('android') || ua.includes('iphone')) {
    deviceType = 'mobile';
  } else if (ua.includes('tablet') || ua.includes('ipad')) {
    deviceType = 'tablet';
  }

  return { browser, os, deviceType };
}

export function getClientIP(req: Request): string {
  const forwarded = req.headers['x-forwarded-for'] as string;
  const realIP = req.headers['x-real-ip'] as string;
  const cfConnectingIP = req.headers['cf-connecting-ip'] as string;

  if (forwarded) {
    return forwarded.split(',')[0].trim();
  }
  if (realIP) {
    return realIP;
  }
  if (cfConnectingIP) {
    return cfConnectingIP;
  }

  return req.connection.remoteAddress || req.socket.remoteAddress || '127.0.0.1';
}

export async function getLocationFromIP(ip: string): Promise<{ country?: string; city?: string; timezone?: string }> {
  // Skip for localhost/private IPs
  if (ip === '127.0.0.1' || ip.startsWith('192.168.') || ip.startsWith('10.') || ip.startsWith('172.')) {
    return { country: 'Local', city: 'Localhost', timezone: 'UTC' };
  }

  try {
    // You can integrate with services like ipapi.co, ipgeolocation.io, or ip-api.com
    // For now, we'll return basic info to avoid external dependencies
    return { country: 'Unknown', city: 'Unknown', timezone: 'UTC' };
  } catch (error) {
    console.error('Error getting location from IP:', error);
    return { country: 'Unknown', city: 'Unknown', timezone: 'UTC' };
  }
}

export function extractDeviceInfo(req: Request): DeviceInfo {
  const userAgent = req.headers['user-agent'] || '';
  const { browser, os, deviceType } = parseUserAgent(userAgent);
  const ipAddress = getClientIP(req);

  return {
    deviceInfo: userAgent,
    deviceType,
    browser,
    os,
    ipAddress,
  };
}

