});

type AppSettingsData = z.infer<typeof appSettingsSchema>;

interface AppSettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
}

export function AppSettingsModal({ isOpen, onClose }: AppSettingsModalProps) {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [newBannerUrl, setNewBannerUrl] = useState("");

  const { data: settings } = useQuery({
    queryKey: ["/api/settings"],
    enabled: isOpen,
  });

  const { data: categories = [] } = useQuery({
    queryKey: ["/api/categories"],
    enabled: isOpen,
  });

  const form = useForm<AppSettingsData>({
    resolver: zodResolver(appSettingsSchema),
    defaultValues: {
      appName: "",
      appLogo: "",
      primaryColor: "#3b82f6",
      secondaryColor: "#1f2937",
      bannerImages: [],
      footerText: "",
      heroTitle: "",
      heroSubtitle: "",
      heroButtonText: "",
      statsTitle: "",
      stat1Label: "",
      stat1Value: "",
      stat2Label: "",
      stat2Value: "",
      stat3Label: "",
      stat3Value: "",
      stat4Label: "",
      stat4Value: "",
      aboutTitle: "",
      aboutDescription: "",
      featuresTitle: "",
      feature1Title: "",
      feature1Description: "",
      feature2Title: "",
      feature2Description: "",
      feature3Title: "",
      feature3Description: "",
      contactTitle: "",
      contactDescription: "",
      contactEmail: "",
      contactPhone: "",
      allowPublicRegistration: false,
      publicUserAccessCategories: [],
    },
  });

  useEffect(() => {
    if (settings) {
      form.reset({
        appName: settings.appName || "",
        appLogo: settings.appLogo || "",
        primaryColor: settings.primaryColor || "#3b82f6",
        secondaryColor: settings.secondaryColor || "#1f2937",
        bannerImages: settings.bannerImages || [],
        footerText: settings.footerText || "",
        heroTitle: settings.heroTitle || "",
        heroSubtitle: settings.heroSubtitle || "",
        heroButtonText: settings.heroButtonText || "",
        statsTitle: settings.statsTitle || "",
        stat1Label: settings.stat1Label || "",
        stat1Value: settings.stat1Value || "",
        stat2Label: settings.stat2Label || "",
        stat2Value: settings.stat2Value || "",
        stat3Label: settings.stat3Label || "",
