import React, { useState, useEffect } from 'react';
import { useMutation, useQueryClient, useQuery } from '@tanstack/react-query';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Switch } from '@/components/ui/switch';
import { useToast } from '@/hooks/use-toast';
import { apiRequest } from '@/lib/queryClient';
import { Calendar, Clock, Users, Video, MapPin, DollarSign, Upload, ImageIcon } from 'lucide-react';

interface EventModalProps {
  isOpen: boolean;
  onClose: () => void;
  event?: any;
  mode: 'create' | 'edit';
}

export default function EventModal({ isOpen, onClose, event, mode }: EventModalProps) {
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    type: 'webinar',
    status: 'active',
    instructorName: '',
    instructorEmail: '',
    maxParticipants: 100,
    price: 0,
    meetingLink: '',
    startDate: '',
    endDate: '',
    location: '',
    coverImage: '',
    isPublic: true,
  });

  const [coverImageFile, setCoverImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string>('');

  const { toast } = useToast();
  const queryClient = useQueryClient();

  // Removed category selection as requested

  useEffect(() => {
    if (event && mode === 'edit') {
      setFormData({
        title: event.title || '',
        description: event.description || '',
        type: event.type || 'webinar',
        status: event.status || 'active',
        instructorName: event.instructorName || '',
        instructorEmail: event.instructorEmail || '',
        maxParticipants: event.maxParticipants || 100,
        price: event.price || 0,
        meetingLink: event.meetingLink || '',
        startDate: event.startDate ? new Date(event.startDate).toISOString().slice(0, 16) : '',
        endDate: event.endDate ? new Date(event.endDate).toISOString().slice(0, 16) : '',
        location: event.location || '',
        coverImage: event.coverImage || '',
        isPublic: event.isPublic !== undefined ? event.isPublic : true,
      });
    } else if (mode === 'create') {
      setFormData({
        title: '',
        description: '',
        type: 'webinar',
        status: 'active',
        instructorName: '',
        instructorEmail: '',
        maxParticipants: 100,
        price: 0,
        meetingLink: '',
        startDate: '',
        endDate: '',
        location: '',
        coverImage: '',
        isPublic: true,
      });
    }
  }, [event, mode, isOpen]);

  const createMutation = useMutation({
    mutationFn: (data: any) => apiRequest('POST', '/api/admin/events', data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/events'] });
      queryClient.invalidateQueries({ queryKey: ['/api/admin/events'] });
      toast({
        title: 'Success',
        description: 'Event created successfully',
      });
      onClose();
    },
    onError: (error: any) => {
      toast({
        title: 'Error',
        description: error.message || 'Failed to create event',
        variant: 'destructive',
      });
    },
  });

  const updateMutation = useMutation({
    mutationFn: (data: any) => apiRequest('PUT', `/api/admin/events/${event?.id}`, data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/events'] });
      queryClient.invalidateQueries({ queryKey: ['/api/admin/events'] });
      toast({
        title: 'Success',
        description: 'Event updated successfully',
      });
      onClose();
    },
    onError: (error: any) => {
      toast({
        title: 'Error',
        description: error.message || 'Failed to update event',
        variant: 'destructive',
      });
    },
  });

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.title || !formData.startDate || !formData.endDate) {
      toast({
        title: 'Error',
        description: 'Title, start date, and end date are required',
        variant: 'destructive',
      });
      return;
    }

    let coverImageUrl = formData.coverImage;

    // Upload cover image if a new file is selected
    if (coverImageFile) {
      try {
        const uploadFormData = new FormData();
        uploadFormData.append('coverImage', coverImageFile);

        const uploadResponse = await fetch('/api/upload', {
          method: 'POST',
          body: uploadFormData,
          credentials: 'include',
        });

        if (uploadResponse.ok) {
          const uploadResult = await uploadResponse.json();
          coverImageUrl = uploadResult.url || uploadResult.coverImage;
        } else {
          throw new Error('Image upload failed');
        }
      } catch (error) {
        toast({
          title: 'Error',
          description: 'Failed to upload cover image',
          variant: 'destructive',
        });
        return;
      }
    }

    const submitData = {
      ...formData,
      coverImage: coverImageUrl,
      maxParticipants: parseInt(formData.maxParticipants.toString()),
      price: formData.price.toString(), // Keep as string per schema
      startDate: new Date(formData.startDate).toISOString(),
      endDate: new Date(formData.endDate).toISOString(),
    };

    if (mode === 'create') {
      createMutation.mutate(submitData);
    } else {
      updateMutation.mutate(submitData);
    }
  };

  const handleChange = (field: string, value: any) => {
    setFormData(prev => ({
      ...prev,
      [field]: value,
    }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setCoverImageFile(file);

      // Create preview
      const reader = new FileReader();
      reader.onload = (event) => {
        setImagePreview(event.target?.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-4xl max-h-[80vh] overflow-y-auto">
        <DialogHeader>
