                        </SelectContent>
                      </Select>
                    </div>

                    <div className="space-y-2">
                      <Label htmlFor="language">Language</Label>
                      <Select value={formData.language} onValueChange={(value) => handleChange('language', value)}>
                        <SelectTrigger>
                          <SelectValue placeholder="Select language" />
