import { useEffect, useState } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { CheckCircle, Eye, ArrowRight, Bookmark, BookmarkCheck, History, Star, MessageCircle } from "lucide-react";
import { VideoCompletionBadge } from "@/components/video-completion-badge";
import { VideoRating } from "@/components/video-rating";
import { VideoComments } from "@/components/video-comments";
import { RelatedVideosList } from "@/components/related-videos-list";
import { useToast } from "@/hooks/use-toast";
import type { VideoWithCategory } from "@shared/schema";

interface VideoPlayerModalProps {
  video: VideoWithCategory;
  isOpen: boolean;
  onClose: () => void;
  onNext?: () => void;
}

export function VideoPlayerModal({ video, isOpen, onClose, onNext }: VideoPlayerModalProps) {
  const [isCompleted, setIsCompleted] = useState(video.isCompleted || false);
  const [isBookmarked, setIsBookmarked] = useState(video.isBookmarked || false);
  const [watchStartTime, setWatchStartTime] = useState<Date | null>(null);
  const queryClient = useQueryClient();
  const { toast } = useToast();

  const recordViewMutation = useMutation({
    mutationFn: async (videoId: number) => {
      const response = await fetch(`/api/videos/${videoId}/view`, {
        method: "POST",
        credentials: "include",
      });
      if (!response.ok) throw new Error("Failed to record view");
    },
  });

  const recordWatchHistoryMutation = useMutation({
    mutationFn: async ({ videoId, watchDuration }: { videoId: number; watchDuration: number }) => {
      const response = await fetch("/api/watch-history", {
        method: "POST",
        credentials: "include",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          videoId,
          watchDuration,
          progressPercentage: Math.min(100, Math.round((watchDuration / 300) * 100)), // Assume 5min videos for demo
          deviceInfo: navigator.userAgent,
        }),
      });
      if (!response.ok) throw new Error("Failed to record watch history");
    },
  });

  const toggleCompletionMutation = useMutation({
    mutationFn: async ({ videoId, isCompleting }: { videoId: number; isCompleting: boolean }) => {
      const response = await fetch(`/api/videos/${videoId}/complete`, {
        method: isCompleting ? "POST" : "DELETE",
        credentials: "include",
        headers: {
          "Content-Type": "application/json",
        },
        body: isCompleting ? JSON.stringify({ watchTime: 0 }) : undefined,
      });
      if (!response.ok) throw new Error("Failed to update completion status");
    },
    onSuccess: (_, { isCompleting }) => {
      setIsCompleted(isCompleting);
      queryClient.invalidateQueries({ queryKey: ["/api/videos"] });
      toast({
        title: isCompleting ? "Video completed!" : "Completion removed",
        description: isCompleting ? "Great job on finishing this video." : "Video marked as incomplete.",
      });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to update completion status. Please try again.",
        variant: "destructive",
      });
    },
  });

  const toggleBookmarkMutation = useMutation({
    mutationFn: async ({ videoId, isBookmarking }: { videoId: number; isBookmarking: boolean }) => {
      const response = await fetch(`/api/videos/${videoId}/bookmark`, {
        method: isBookmarking ? "POST" : "DELETE",
        credentials: "include",
      });
      if (!response.ok) throw new Error("Failed to update bookmark status");
    },
    onSuccess: (_, { isBookmarking }) => {
      setIsBookmarked(isBookmarking);
      queryClient.invalidateQueries({ queryKey: ["/api/videos"] });
      toast({
        title: isBookmarking ? "Video bookmarked!" : "Bookmark removed",
        description: isBookmarking ? "Added to your bookmarks." : "Removed from bookmarks.",
      });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to update bookmark status. Please try again.",
        variant: "destructive",
      });
    },
  });

  useEffect(() => {
    if (isOpen) {
      recordViewMutation.mutate(video.id);
      setIsCompleted(video.isCompleted || false);
      setIsBookmarked(video.isBookmarked || false);
      setWatchStartTime(new Date());
    }
  }, [isOpen, video.id, video.isCompleted, video.isBookmarked]);

  useEffect(() => {
    // Record watch history when modal closes
    return () => {
      if (watchStartTime && isOpen) {
        const watchDuration = Math.floor((Date.now() - watchStartTime.getTime()) / 1000);
        if (watchDuration > 5) { // Only record if watched for more than 5 seconds
          recordWatchHistoryMutation.mutate({ videoId: video.id, watchDuration });
        }
      }
    };
  }, [isOpen, watchStartTime]);

  const handleMarkComplete = () => {
    toggleCompletionMutation.mutate({ videoId: video.id, isCompleting: !isCompleted });
  };

  const handleToggleBookmark = () => {
    toggleBookmarkMutation.mutate({ videoId: video.id, isBookmarking: !isBookmarked });
  };

  const handleGoToNext = () => {
    if (onNext) {
      onNext();
    }
  };

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="max-w-7xl w-[98vw] h-[95vh] max-h-[95vh] p-4 overflow-hidden flex flex-col">
        <DialogHeader className="flex-shrink-0 pb-4">
          <DialogTitle className="text-xl font-bold leading-tight pr-8">
            {video.title}
          </DialogTitle>
        </DialogHeader>

        {/* YouTube-style Layout: Left Video Player, Right Video List */}
        <div className="flex-1 overflow-hidden flex gap-6">
          {/* Left Column - Video Player and Info */}
          <div className="flex-1 flex flex-col">
            {/* Video Player */}
            <div className="aspect-video bg-black rounded-lg mb-4 flex-shrink-0">
              <iframe
                src={`https://www.youtube.com/embed/${video.youtubeId}?autoplay=1&rel=0&modestbranding=1`}
                title={video.title}
                className="w-full h-full rounded-lg"
                allowFullScreen
                allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
              />
            </div>

            {/* Video Info Below Player */}
            <div className="flex-1 overflow-y-auto space-y-4 scrollbar-thin">
              {/* Action Bar */}
              <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3 sm:gap-4">
                {/* Video Meta */}
                <div className="flex flex-wrap items-center gap-2 sm:gap-4 text-sm">
                  {video.category && (
                    <Badge variant="secondary" className="text-xs">{video.category.name}</Badge>
                  )}
                  <span className="text-gray-500">{video.duration || "N/A"}</span>
                  <div className="flex items-center text-gray-500">
                    <Eye className="h-3 w-3 sm:h-4 sm:w-4 mr-1" />
                    <span>{video.viewCount} views</span>
                  </div>
                </div>

                {/* Action Buttons */}
                <div className="flex items-center gap-2 flex-wrap">
                  <VideoCompletionBadge isCompleted={isCompleted} size="sm" />

                  <Button 
                    variant="outline"
                    size="sm"
                    onClick={handleToggleBookmark}
                    disabled={toggleBookmarkMutation.isPending}
                    className="flex-shrink-0"
                  >
                    {isBookmarked ? (
                      <BookmarkCheck className="h-3 w-3 sm:h-4 sm:w-4 mr-1" />
                    ) : (
                      <Bookmark className="h-3 w-3 sm:h-4 sm:w-4 mr-1" />
                    )}
                    <span className="hidden sm:inline">
                      {isBookmarked ? "Bookmarked" : "Bookmark"}
                    </span>
                  </Button>

                  <Button 
                    variant={isCompleted ? "outline" : "default"}
                    size="sm"
                    onClick={handleMarkComplete}
                    disabled={toggleCompletionMutation.isPending}
                    className="flex-shrink-0"
                  >
                    <CheckCircle className="h-3 w-3 sm:h-4 sm:w-4 mr-1" />
                    <span className="hidden sm:inline">
                      {isCompleted ? "Mark Incomplete" : "Mark Complete"}
                    </span>
                  </Button>

                  {isCompleted && onNext && (
                    <Button 
                      variant="default"
                      size="sm"
                      onClick={handleGoToNext}
                      className="bg-green-600 hover:bg-green-700 flex-shrink-0"
                    >
                      <ArrowRight className="h-3 w-3 sm:h-4 sm:w-4 mr-1" />
                      <span className="hidden sm:inline">Next Video</span>
                      <span className="sm:hidden">Next</span>
                    </Button>
                  )}
                </div>
              </div>

              {/* Description */}
              {video.description && (
                <div className="space-y-2">
                  <h4 className="font-medium text-gray-900 text-sm sm:text-base">Description</h4>
                  <p className="text-gray-600 whitespace-pre-wrap text-sm leading-relaxed">
                    {video.description}
                  </p>
                </div>
              )}

              {/* Tags */}
              {video.tags && video.tags.length > 0 && (
                <div className="space-y-2">
                  <h4 className="font-medium text-gray-900 text-sm sm:text-base">Tags</h4>
                  <div className="flex flex-wrap gap-1.5 sm:gap-2">
                    {video.tags.map((tag, index) => (
                      <Badge key={index} variant="outline" className="text-xs">
                        {tag}
                      </Badge>
                    ))}
                  </div>
                </div>
              )}

              {/* Ratings and Comments Tabs */}
              <div className="border-t pt-4">
                <Tabs defaultValue="rating" className="w-full">
                  <TabsList className="grid w-full grid-cols-2 mb-4">
                    <TabsTrigger value="rating" className="text-sm font-medium">
                      <Star className="h-4 w-4 mr-1" />
                      Rating
                      {video.averageRating && (
                        <Badge variant="secondary" className="ml-1 text-xs">
                          {video.averageRating.toFixed(1)}
                        </Badge>
                      )}
                    </TabsTrigger>
                    <TabsTrigger value="comments" className="text-sm font-medium">
                      <MessageCircle className="h-4 w-4 mr-1" />
                      Comments
                      {video.commentsCount && (
                        <Badge variant="secondary" className="ml-1 text-xs">
                          {video.commentsCount}
                        </Badge>
                      )}
                    </TabsTrigger>
                  </TabsList>

                  <TabsContent value="rating" className="mt-4">
                    <VideoRating
                      video={video}
                      userRating={video.userRating}
                      onRatingSubmit={() => {
                        queryClient.invalidateQueries({ queryKey: ["/api/videos"] });
                      }}
                    />
                  </TabsContent>

                  <TabsContent value="comments" className="mt-4">
                    <VideoComments video={video} />
                  </TabsContent>
                </Tabs>
              </div>
            </div>
          </div>

          {/* Right Column - Related Videos from Same Category */}
          <div className="w-80 flex-shrink-0">
            <RelatedVideosList 
              currentVideo={video} 
              onVideoSelect={onNext} 
            />
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

client/src/components/video-rating.tsx.content:
import { useState } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { Star, StarOff } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import { type VideoWithCategory } from "@shared/schema";

interface VideoRatingProps {
  video: VideoWithCategory;
  userRating?: number;
  onRatingSubmit?: () => void;
}

export function VideoRating({ video, userRating, onRatingSubmit }: VideoRatingProps) {
  const [rating, setRating] = useState(userRating || 0);
  const [hoverRating, setHoverRating] = useState(0);
  const [review, setReview] = useState("");
  const [showReviewForm, setShowReviewForm] = useState(false);
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const ratingMutation = useMutation({
    mutationFn: async (data: { rating: number; review?: string }) => {
      return await apiRequest("POST", `/api/videos/${video.id}/rating`, data);
    },
    onSuccess: () => {
      toast({
        title: "Rating submitted",
        description: "Thank you for your feedback!",
      });
      queryClient.invalidateQueries({ queryKey: ["/api/videos"] });
      onRatingSubmit?.();
      setShowReviewForm(false);
      setReview("");
    },
    onError: (error: Error) => {
      toast({
        title: "Error",
        description: error.message || "Failed to submit rating",
        variant: "destructive",
      });
    },
  });

  const handleStarClick = (starRating: number) => {
    setRating(starRating);
    if (starRating > 0) {
      setShowReviewForm(true);
    }
  };

  const handleSubmit = () => {
    if (rating > 0) {
      ratingMutation.mutate({ rating, review: review.trim() || undefined });
    }
  };

  const renderStars = () => {
    return Array.from({ length: 5 }, (_, index) => {
      const starValue = index + 1;
      const isActive = starValue <= (hoverRating || rating);

      return (
        <button
          key={index}
          type="button"
          onClick={() => handleStarClick(starValue)}
          onMouseEnter={() => setHoverRating(starValue)}
          onMouseLeave={() => setHoverRating(0)}
          className="p-1 transition-transform hover:scale-110"
        >
          {isActive ? (
            <Star className="h-6 w-6 text-yellow-400 fill-yellow-400" />
          ) : (
            <StarOff className="h-6 w-6 text-gray-300" />
          )}
        </button>
      );
    });
  };

  return (
    <Card className="w-full">
      <CardHeader className="pb-3">
        <CardTitle className="text-lg flex items-center justify-between">
          <span>Rate this video</span>
          <div className="flex items-center gap-2">
            {video.averageRating && (
              <Badge variant="secondary" className="bg-yellow-100 text-yellow-800">
                <Star className="h-3 w-3 mr-1 fill-yellow-400 text-yellow-400" />
                {video.averageRating.toFixed(1)} ({video.totalRatings} reviews)
              </Badge>
            )}
          </div>
        </CardTitle>
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="flex items-center gap-1">
          {renderStars()}
          <span className="ml-2 text-sm text-gray-600">
            {rating > 0 ? `${rating} out of 5 stars` : "Click to rate"}
          </span>
        </div>

        {showReviewForm && (
          <div className="space-y-3">
            <Textarea
              placeholder="Write a review (optional)..."
              value={review}
              onChange={(e) => setReview(e.target.value)}
              className="min-h-[80px]"
            />
            <div className="flex gap-2">
              <Button
                onClick={handleSubmit}
                disabled={rating === 0 || ratingMutation.isPending}
                size="sm"
              >
                Submit Rating
              </Button>
              <Button
                variant="outline"
                onClick={() => {
                  setShowReviewForm(false);
                  setRating(userRating || 0);
                  setReview("");
                }}
                size="sm"
              >
                Cancel
              </Button>
            </div>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

client/src/hooks/use-auth.tsx.content:
import { createContext, ReactNode, useContext } from "react";
import {
  useQuery,
  useMutation,
  UseMutationResult,
} from "@tanstack/react-query";
import { insertUserSchema, User as SelectUser, InsertUser } from "@shared/schema";
import { getQueryFn, apiRequest, queryClient } from "../lib/queryClient";
import { useToast } from "@/hooks/use-toast";

type AuthContextType = {
  user: SelectUser | null;
  isLoading: boolean;
  error: Error | null;
  loginMutation: UseMutationResult<SelectUser, Error, LoginData>;
  logoutMutation: UseMutationResult<void, Error, void>;
  registerMutation: UseMutationResult<{ message: string; email: string }, Error, InsertUser>;
  verifyOtpMutation: UseMutationResult<{ message: string; user: SelectUser }, Error, { email: string; code: string }>;
  resendOtpMutation: UseMutationResult<{ message: string }, Error, { email: string }>;
};

type LoginData = Pick<InsertUser, "email" | "password">;

export const AuthContext = createContext<AuthContextType | null>(null);

export function AuthProvider({ children }: { children: ReactNode }) {
  const { toast } = useToast();
  const {
    data: user,
    error,
    isLoading,
  } = useQuery<SelectUser | undefined, Error>({
    queryKey: ["/api/user"],
    queryFn: getQueryFn({ on401: "returnNull" }),
  });

  const loginMutation = useMutation({
    mutationFn: async (credentials: LoginData) => {
      const res = await apiRequest("POST", "/api/login", credentials);
      return await res.json();
    },
    onSuccess: (user: SelectUser) => {
      queryClient.setQueryData(["/api/user"], user);
      toast({
        title: "Login successful",
        description: "Welcome back!",
      });
    },
    onError: (error: Error) => {
      toast({
        title: "Login failed",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const registerMutation = useMutation({
    mutationFn: async (credentials: InsertUser) => {
      const res = await apiRequest("POST", "/api/register", credentials);
      return await res.json();
    },
    onSuccess: (response: { message: string; email: string; testOtp?: string }) => {
      toast({
        title: "Registration successful",
        description: response.message,
        duration: response.testOtp ? 10000 : 5000, // Show longer if OTP is included
      });
    },
    onError: (error: Error) => {
      toast({
        title: "Registration failed",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const verifyOtpMutation = useMutation({
    mutationFn: async ({ email, code }: { email: string; code: string }) => {
      const res = await apiRequest("POST", "/api/verify-otp", { email, code });
      return await res.json();
    },
    onSuccess: (response: { message: string; user: SelectUser }) => {
      queryClient.setQueryData(["/api/user"], response.user);
      toast({
        title: "Email verified",
        description: "Welcome to Zmartclass!",
      });
    },
    onError: (error: Error) => {
      toast({
        title: "Verification failed",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const resendOtpMutation = useMutation({
    mutationFn: async ({ email }: { email: string }) => {
      const res = await apiRequest("POST", "/api/resend-otp", { email });
      return await res.json();
    },
    onSuccess: (response: { message: string }) => {
      toast({
        title: "Code sent",
        description: response.message,
      });
    },
    onError: (error: Error) => {
      toast({
        title: "Failed to send code",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const logoutMutation = useMutation({
    mutationFn: async () => {
      await apiRequest("POST", "/api/logout");
    },
    onSuccess: () => {
      queryClient.setQueryData(["/api/user"], null);
      toast({
        title: "Logged out",
        description: "See you next time!",
      });
    },
    onError: (error: Error) => {
      toast({
        title: "Logout failed",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  return (
    <AuthContext.Provider
      value={{
        user: user ?? null,
        isLoading,
        error,
        loginMutation,
        logoutMutation,
        registerMutation,
        verifyOtpMutation,
        resendOtpMutation,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
}

client/src/hooks/use-mobile.tsx.content:
import * as React from "react"

const MOBILE_BREAKPOINT = 768

export function useIsMobile() {
  const [isMobile, setIsMobile] = React.useState<boolean | undefined>(undefined)

  React.useEffect(() => {
    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`)
    const onChange = () => {
      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    }
    mql.addEventListener("change", onChange)
    setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    return () => mql.removeEventListener("change", onChange)
  }, [])

  return !!isMobile
}

client/src/hooks/use-toast.ts.content:
import * as React from "react"

import type {
  ToastActionElement,
  ToastProps,
} from "@/components/ui/toast"

const TOAST_LIMIT = 1
const TOAST_REMOVE_DELAY = 1000000

type ToasterToast = ToastProps & {
  id: string
  title?: React.ReactNode
  description?: React.ReactNode
  action?: ToastActionElement
}

const actionTypes = {
  ADD_TOAST: "ADD_TOAST",
  UPDATE_TOAST: "UPDATE_TOAST",
  DISMISS_TOAST: "DISMISS_TOAST",
  REMOVE_TOAST: "REMOVE_TOAST",
} as const

let count = 0

function genId() {
  count = (count + 1) % Number.MAX_SAFE_INTEGER
  return count.toString()
}

type ActionType = typeof actionTypes

type Action =
  | {
      type: ActionType["ADD_TOAST"]
      toast: ToasterToast
    }
  | {
      type: ActionType["UPDATE_TOAST"]
      toast: Partial<ToasterToast>
    }
  | {
      type: ActionType["DISMISS_TOAST"]
      toastId?: ToasterToast["id"]
    }
  | {
      type: ActionType["REMOVE_TOAST"]
      toastId?: ToasterToast["id"]
    }

interface State {
  toasts: ToasterToast[]
}

const toastTimeouts = new Map<string, ReturnType<typeof setTimeout>>()

const addToRemoveQueue = (toastId: string) => {
  if (toastTimeouts.has(toastId)) {
    return
  }

  const timeout = setTimeout(() => {
    toastTimeouts.delete(toastId)
    dispatch({
      type: "REMOVE_TOAST",
      toastId: toastId,
    })
  }, TOAST_REMOVE_DELAY)

  toastTimeouts.set(toastId, timeout)
}

export const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case "ADD_TOAST":
      return {
        ...state,
        toasts: [action.toast, ...state.toasts].slice(0, TOAST_LIMIT),
      }

    case "UPDATE_TOAST":
      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === action.toast.id ? { ...t, ...action.toast } : t
        ),
      }

    case "DISMISS_TOAST": {
      const { toastId } = action

      // ! Side effects ! - This could be extracted into a dismissToast() action,
      // but I'll keep it here for simplicity
      if (toastId) {
        addToRemoveQueue(toastId)
      } else {
        state.toasts.forEach((toast) => {
          addToRemoveQueue(toast.id)
        })
      }

      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === toastId || toastId === undefined
            ? {
                ...t,
                open: false,
              }
            : t
        ),
      }
    }
    case "REMOVE_TOAST":
      if (action.toastId === undefined) {
        return {
          ...state,
          toasts: [],
        }
      }
      return {
        ...state,
        toasts: state.toasts.filter((t) => t.id !== action.toastId),
      }
  }
}

const listeners: Array<(state: State) => void> = []

let memoryState: State = { toasts: [] }

function dispatch(action: Action) {
  memoryState = reducer(memoryState, action)
  listeners.forEach((listener) => {
    listener(memoryState)
  })
}

type Toast = Omit<ToasterToast, "id">

function toast({ ...props }: Toast) {
  const id = genId()

  const update = (props: ToasterToast) =>
    dispatch({
      type: "UPDATE_TOAST",
      toast: { ...props, id },
    })
  const dismiss = () => dispatch({ type: "DISMISS_TOAST", toastId: id })

  dispatch({
    type: "ADD_TOAST",
    toast: {
      ...props,
      id,
      open: true,
      onOpenChange: (open) => {
        if (!open) dismiss()
      },
    },
  })

  return {
    id: id,
    dismiss,
    update,
  }
}

function useToast() {
  const [state, setState] = React.useState<State>(memoryState)

  React.useEffect(() => {
    listeners.push(setState)
    return () => {
      const index = listeners.indexOf(setState)
      if (index > -1) {
        listeners.splice(index, 1)
      }
    }
  }, [state])

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) => dispatch({ type: "DISMISS_TOAST", toastId }),
  }
}

export { useToast, toast }

