import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useParams, useLocation } from 'wouter';
import { useMutation, useQueryClient, useQuery } from '@tanstack/react-query';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Switch } from '@/components/ui/switch';
import { Badge } from '@/components/ui/badge';
import { useToast } from '@/hooks/use-toast';
import { apiRequest } from '@/lib/queryClient';
import { ArrowLeft, Save, Upload, Image, X, Tag, Eye } from 'lucide-react';
import RichTextEditor from '@/components/rich-text-editor';

export default function BlogEditorPage() {
  const { id } = useParams();
  const [, navigate] = useLocation();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isUploading, setIsUploading] = useState(false);
  const [tagInput, setTagInput] = useState('');
  const [autoSaveEnabled, setAutoSaveEnabled] = useState(false);
  const [lastSaved, setLastSaved] = useState<Date | null>(null);
  const [autoSaveStatus, setAutoSaveStatus] = useState<'idle' | 'saving' | 'saved' | 'error'>('idle');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const autoSaveTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  const [formData, setFormData] = useState({
    title: '',
    slug: '',
    content: '',
    excerpt: '',
    coverImage: '',
    author: '',
    authorEmail: '',
    status: 'draft',
    categoryId: '',
    tags: [] as string[],
    isPublic: true,
    isFeatured: false,
    publishedAt: '',
  });

  const isEdit = !!id;

  // Fetch blog post for editing
  const { data: post, isLoading: postLoading } = useQuery({
    queryKey: ['/api/admin/blog', id],
    queryFn: async () => {
      const response = await fetch(`/api/blog/id/${id}`);
      if (!response.ok) throw new Error('Failed to fetch blog post');
      return response.json();
    },
    enabled: isEdit,
  });

  // Fetch categories
  const { data: categories = [] } = useQuery({
    queryKey: ['/api/categories'],
  });

  useEffect(() => {
    if (post && isEdit) {
      setFormData({
        title: post.title || '',
        slug: post.slug || '',
        content: post.content || '',
        excerpt: post.excerpt || '',
        coverImage: post.coverImage || '',
        author: post.author || '',
        authorEmail: post.authorEmail || '',
        status: post.status || 'draft',
        categoryId: post.categoryId ? post.categoryId.toString() : '',
        tags: post.tags || [],
        isPublic: post.isPublic !== undefined ? post.isPublic : true,
        isFeatured: post.isFeatured !== undefined ? post.isFeatured : false,
        publishedAt: post.publishedAt ? new Date(post.publishedAt).toISOString().slice(0, 16) : '',
      });
    }
  }, [post, isEdit]);

  // Cleanup auto-save timeout on unmount
  useEffect(() => {
    return () => {
      if (autoSaveTimeoutRef.current) {
        clearTimeout(autoSaveTimeoutRef.current);
      }
    };
  }, []);

  const generateSlug = (title: string) => {
    return title
      .toLowerCase()
      .replace(/[^a-z0-9 -]/g, '')
      .replace(/\s+/g, '-')
      .replace(/-+/g, '-')
      .trim('-');
  };

  const createMutation = useMutation({
    mutationFn: (data: any) => apiRequest('POST', '/api/admin/blog', data),
    onSuccess: () => {
      setIsSubmitting(false);
      queryClient.invalidateQueries({ queryKey: ['/api/admin/blog'] });
      toast({
        title: 'Success',
        description: 'Blog post created successfully',
      });
      navigate('/admin');
    },
    onError: (error: any) => {
      setIsSubmitting(false);
      toast({
        title: 'Error',
        description: error.message || 'Failed to create blog post',
        variant: 'destructive',
      });
    },
  });

  const updateMutation = useMutation({
    mutationFn: (data: any) => apiRequest('PUT', `/api/admin/blog/${id}`, data),
    onSuccess: () => {
      setIsSubmitting(false);
      queryClient.invalidateQueries({ queryKey: ['/api/admin/blog'] });
      setLastSaved(new Date());
      setAutoSaveStatus('saved');
      // Only show success toast for manual saves (when navigating)
      if (!autoSaveEnabled || formData.status === 'published') {
        toast({
          title: 'Success',
          description: 'Blog post updated successfully',
        });
        navigate('/admin');
      }
    },
    onError: (error: any) => {
      setIsSubmitting(false);
      setAutoSaveStatus('error');
      toast({
        title: 'Error',
        description: error.message || 'Failed to update blog post',
        variant: 'destructive',
      });
    },
  });

  // Auto-save mutation for background saves
  const autoSaveMutation = useMutation({
    mutationFn: (data: any) => apiRequest('PUT', `/api/admin/blog/${id}`, data),
    onMutate: () => {
      setAutoSaveStatus('saving');
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/admin/blog'] });
      setLastSaved(new Date());
      setAutoSaveStatus('saved');
      // Hide the "saved" status after 3 seconds
      setTimeout(() => {
        setAutoSaveStatus('idle');
      }, 3000);
    },
    onError: () => {
      setAutoSaveStatus('error');
      setTimeout(() => {
        setAutoSaveStatus('idle');
      }, 3000);
    },
  });

  // Debounced auto-save function - COMPLETELY DISABLED
  const debouncedAutoSave = useCallback((data: any) => {
    // AUTO-SAVE COMPLETELY DISABLED TO PREVENT UNWANTED SAVES
    // All saving is now manual only via the "Update" or "Publish" button
    console.log('Auto-save disabled - no automatic saving will occur');
    return;
  }, []);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Prevent double submissions
    if (isSubmitting) {
      console.log('Form submission already in progress, ignoring duplicate submission');
      return;
    }

    setIsSubmitting(true);

    // DEBUGGING: Log all form submissions to identify unwanted submissions
    console.log('handleSubmit called - Form submission triggered');
    console.log('Form data:', formData);
    console.log('Is edit mode:', isEdit);

    // Enhanced validation with detailed logging
    console.log('Validating form data:');
    console.log('Title:', formData.title);
    console.log('Content:', formData.content);
    console.log('Title length:', formData.title?.length || 0);
    console.log('Content length:', formData.content?.length || 0);

    if (!formData.title || formData.title.trim() === '') {
      setIsSubmitting(false);
      toast({
        title: 'Error',
        description: 'Title is required',
        variant: 'destructive',
      });
      return;
    }

    if (!formData.content || formData.content.trim() === '' || formData.content === '<p></p>') {
      setIsSubmitting(false);
      toast({
        title: 'Error',
        description: 'Content is required',
        variant: 'destructive',
      });
      return;
    }

    const submitData = {
      ...formData,
      slug: formData.slug || generateSlug(formData.title),
      categoryId: formData.categoryId && formData.categoryId !== 'none' ? parseInt(formData.categoryId) : null,
      publishedAt: formData.publishedAt ? new Date(formData.publishedAt).toISOString() : new Date().toISOString(),
    };

    console.log('About to submit data:', submitData);

    if (isEdit) {
      updateMutation.mutate(submitData);
    } else {
      createMutation.mutate(submitData);
    }
  };

  const handleChange = (field: string, value: any) => {
    console.log(`handleChange called for field: ${field}`);

    const newFormData = {
      ...formData,
      [field]: value,
    };

    // Auto-generate slug when title changes
    if (field === 'title' && value) {
      newFormData.slug = generateSlug(value);
    }

    setFormData(newFormData);

    // AUTO-SAVE COMPLETELY DISABLED
    // No automatic saving will occur - only manual saves via buttons
    console.log('Field updated, no auto-save triggered');
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    try {
      const formDataUpload = new FormData();
      formDataUpload.append('coverImage', file);

      const response = await fetch('/api/upload', {
        method: 'POST',
        body: formDataUpload,
      });

      if (!response.ok) {
        throw new Error('Upload failed');
      }

      const data = await response.json();

      // DEBUGGING: Check if this is triggering auto-save
      console.log('Image uploaded, updating coverImage without triggering auto-save');

      // Direct state update without triggering handleChange to avoid any side effects
      setFormData(prev => ({
        ...prev,
        coverImage: data.url
      }));

      toast({
        title: 'Success',
        description: 'Image uploaded successfully',
      });
    } catch (error) {
      toast({
        title: 'Error',
        description: 'Failed to upload image',
        variant: 'destructive',
      });
    } finally {
      setIsUploading(false);
    }
  };

  const handleAddTag = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && tagInput.trim()) {
      e.preventDefault();
      if (!formData.tags.includes(tagInput.trim())) {
        setFormData(prev => ({
          ...prev,
          tags: [...prev.tags, tagInput.trim()],
        }));
      }
      setTagInput('');
    }
  };

  const handleRemoveTag = (tagToRemove: string) => {
    setFormData(prev => ({
      ...prev,
      tags: prev.tags.filter(tag => tag !== tagToRemove),
    }));
  };

  const handlePreview = () => {
    const previewSlug = formData.slug || generateSlug(formData.title);
    if (previewSlug && isEdit) {
      window.open(`/blog/${previewSlug}`, '_blank');
    } else if (previewSlug) {
      // For new posts, show a preview modal or temporary preview
      toast({
        title: 'Preview',
        description: 'Save the post first to get a full preview. Slug will be: ' + previewSlug,
      });
    } else {
      toast({
        title: 'Error',
        description: 'Please enter a title to generate preview',
        variant: 'destructive',
      });
    }
  };

  if (isEdit && postLoading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-gray-600">Loading blog post...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-16">
            <div className="flex items-center space-x-4">
              <Button
                variant="ghost"
                onClick={() => navigate('/admin')}
                className="flex items-center"
              >
                <ArrowLeft className="h-4 w-4 mr-2" />
                Back to Admin
              </Button>
              <h1 className="text-xl font-semibold text-gray-900">
                {isEdit ? 'Edit Blog Post' : 'Create New Blog Post'}
              </h1>
            </div>
            <div className="flex items-center space-x-3">
              {/* Auto-save controls - only show for existing posts */}
              {isEdit && (
                <div className="flex items-center space-x-2 text-sm">
                  <Switch
                    checked={autoSaveEnabled}
                    onCheckedChange={setAutoSaveEnabled}
                    className="data-[state=checked]:bg-green-600"
                  />
                  <span className="text-gray-600">Auto-save</span>
                  {autoSaveStatus === 'saving' && (
                    <span className="text-blue-600 animate-pulse">Saving...</span>
                  )}
                  {autoSaveStatus === 'saved' && (
                    <span className="text-green-600">✓ Saved</span>
                  )}
                  {autoSaveStatus === 'error' && (
                    <span className="text-red-600">Error</span>
                  )}
                  {lastSaved && autoSaveStatus === 'idle' && (
                    <span className="text-gray-500">
                      Last saved: {lastSaved.toLocaleTimeString()}
                    </span>
                  )}
                </div>
              )}

              <Button
                variant="outline"
                onClick={handlePreview}
                disabled={!formData.slug}
              >
                <Eye className="h-4 w-4 mr-2" />
                Preview
              </Button>
              <Button
                onClick={handleSubmit}
                disabled={createMutation.isPending || updateMutation.isPending || autoSaveMutation.isPending || isSubmitting}
              >
                <Save className="h-4 w-4 mr-2" />
                {isSubmitting ? 'Submitting...' : (isEdit ? 'Update' : 'Publish')}
              </Button>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <form onSubmit={handleSubmit} className="space-y-8" onKeyDown={(e) => {
          if (e.key === 'Enter' && e.target.tagName === 'INPUT') {
            // Prevent form submission on Enter key in input fields
            console.log('Enter key pressed in input, preventing form submission');
            e.preventDefault();
          }
        }}>
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            {/* Main Editor */}
            <div className="lg:col-span-2 space-y-6">
              {/* Title */}
              <div className="space-y-2">
                <Label htmlFor="title" className="text-base font-medium">Title *</Label>
                <Input
                  id="title"
                  value={formData.title}
                  onChange={(e) => handleChange('title', e.target.value)}
                  placeholder="Enter an engaging title for your blog post"
                  className="text-lg"
                  required
                />
              </div>

              {/* Slug */}
              <div className="space-y-2">
                <Label htmlFor="slug" className="text-base font-medium">URL Slug</Label>
                <Input
                  id="slug"
                  value={formData.slug}
                  onChange={(e) => handleChange('slug', e.target.value)}
                  placeholder="auto-generated-from-title"
                />
              </div>

              {/* Content Editor */}
              <div className="space-y-2">
                <Label className="text-base font-medium">Content *</Label>
                <RichTextEditor
                  content={formData.content}
                  onChange={(content) => {
                    // Direct state update with NO auto-save whatsoever
                    console.log('Rich Text Editor content changed, updating state only');
                    setFormData(prev => ({
                      ...prev,
                      content: content
                    }));

                    // AUTO-SAVE COMPLETELY DISABLED
                    // No automatic saving - only manual saves via buttons
                    console.log('Content updated without triggering any saves');
                  }}
                  placeholder="Start writing your blog post..."
                  className="min-h-[500px]"
                />
              </div>
            </div>

            {/* Sidebar */}
            <div className="space-y-6">
              {/* Cover Image */}
              <div className="bg-white p-6 rounded-lg border border-gray-200">
                <Label className="text-base font-medium mb-3 block">Cover Image</Label>
                <div className="space-y-3">
                  <div className="flex gap-2">
                    <Input
                      value={formData.coverImage}
                      onChange={(e) => handleChange('coverImage', e.target.value)}
                      placeholder="Enter image URL or upload"
                      className="flex-1"
                    />
                    <input
                      ref={fileInputRef}
                      type="file"
                      accept="image/*"
                      onChange={handleImageUpload}
                      className="hidden"
                    />
                    <Button
                      type="button"
                      variant="outline"
                      onClick={() => fileInputRef.current?.click()}
                      disabled={isUploading}
                    >
                      <Upload className="h-4 w-4 mr-2" />
                      {isUploading ? 'Uploading...' : 'Upload'}
                    </Button>
                  </div>
                  {formData.coverImage && (
                    <div className="relative">
                      <img
                        src={formData.coverImage}
                        alt="Cover preview"
                        className="w-full h-48 object-cover rounded-lg border"
                      />
                      <Button
                        type="button"
                        variant="outline"
                        size="sm"
                        onClick={() => handleChange('coverImage', '')}
                        className="absolute top-2 right-2"
                      >
                        <X className="h-4 w-4" />
                      </Button>
                    </div>
                  )}
                </div>
              </div>

              {/* Excerpt */}
              <div className="bg-white p-6 rounded-lg border border-gray-200">
                <Label htmlFor="excerpt" className="text-base font-medium mb-3 block">Excerpt</Label>
                <Textarea
                  id="excerpt"
                  value={formData.excerpt}
                  onChange={(e) => handleChange('excerpt', e.target.value)}
                  placeholder="Brief description of the blog post"
                  rows={4}
                />
              </div>

              {/* Metadata */}
              <div className="bg-white p-6 rounded-lg border border-gray-200 space-y-4">
                <h3 className="text-base font-medium">Metadata</h3>

                <div className="space-y-2">
                  <Label htmlFor="author">Author</Label>
                  <Input
                    id="author"
                    value={formData.author}
                    onChange={(e) => handleChange('author', e.target.value)}
                    placeholder="Enter author name"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="authorEmail">Author Email</Label>
                  <Input
                    id="authorEmail"
                    type="email"
                    value={formData.authorEmail}
                    onChange={(e) => handleChange('authorEmail', e.target.value)}
                    placeholder="Enter author email"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="status">Status</Label>
                  <Select value={formData.status} onValueChange={(value) => handleChange('status', value)}>
                    <SelectTrigger>
                      <SelectValue placeholder="Select status" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="draft">📝 Draft</SelectItem>
                      <SelectItem value="published">✅ Published</SelectItem>
                      <SelectItem value="archived">📦 Archived</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="categoryId">Category (Optional)</Label>
                  <Select value={formData.categoryId} onValueChange={(value) => handleChange('categoryId', value)}>
                    <SelectTrigger>
                      <SelectValue placeholder="Select category (optional)" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="none">No Category</SelectItem>
                      {categories.map((category: any) => (
                        <SelectItem key={category.id} value={category.id.toString()}>
                          {category.name}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="publishedAt">Publish Date (Auto-set if empty)</Label>
                  <Input
                    id="publishedAt"
                    type="datetime-local"
                    value={formData.publishedAt}
                    onChange={(e) => handleChange('publishedAt', e.target.value)}
                    placeholder="Will be set to current time if empty"
                  />
                </div>
              </div>

              {/* Tags */}
              <div className="bg-white p-6 rounded-lg border border-gray-200 space-y-4">
                <Label className="text-base font-medium">Tags</Label>
                <div className="flex flex-wrap gap-2 mb-2">
                  {formData.tags.map((tag) => (
                    <Badge key={tag} variant="secondary" className="flex items-center gap-1">
                      <Tag className="h-3 w-3" />
                      {tag}
                      <button
                        type="button"
                        onClick={() => handleRemoveTag(tag)}
                        className="ml-1 hover:text-destructive"
                      >
                        <X className="h-3 w-3" />
                      </button>
                    </Badge>
                  ))}
                </div>
                <Input
                  value={tagInput}
                  onChange={(e) => setTagInput(e.target.value)}
                  onKeyPress={handleAddTag}
                  placeholder="Add tags (press Enter)"
                />
              </div>

              {/* Settings */}
              <div className="bg-white p-6 rounded-lg border border-gray-200 space-y-4">
                <h3 className="text-base font-medium">Settings</h3>

                <div className="flex items-center justify-between">
                  <Label htmlFor="isPublic">Public Post</Label>
                  <Switch
                    id="isPublic"
                    checked={formData.isPublic}
                    onCheckedChange={(checked) => handleChange('isPublic', checked)}
                  />
                </div>

                <div className="flex items-center justify-between">
                  <Label htmlFor="isFeatured">Featured Post</Label>
                  <Switch
                    id="isFeatured"
                    checked={formData.isFeatured}
                    onCheckedChange={(checked) => handleChange('isFeatured', checked)}
                  />
                </div>
              </div>
            </div>
          </div>
        </form>
      </main>
    </div>
  );
}

client/src/pages/blog-post-page.tsx.content:
import React, { useState, useEffect } from 'react';
import { useParams, useLocation } from 'wouter';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Separator } from '@/components/ui/separator';
import { useAuth } from '@/hooks/use-auth';
import { useToast } from '@/hooks/use-toast';
import { apiRequest } from '@/lib/queryClient';
import {
  ArrowLeft,
  Calendar,
  User,
  Eye,
  Heart,
  Share2,
  Bookmark,
  Twitter,
  Facebook,
  Linkedin,
  Link as LinkIcon,
  Clock
} from 'lucide-react';
import { format } from 'date-fns';

export default function BlogPostPage() {
  const { slug } = useParams();
  const [, navigate] = useLocation();
  const { user } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [isBookmarked, setIsBookmarked] = useState(false);
  const [readingTime, setReadingTime] = useState(0);

  // Fetch blog post
  const { data: post, isLoading, error } = useQuery({
    queryKey: ['/api/blog', slug],
    queryFn: async () => {
      const response = await fetch(`/api/blog/${slug}`);
      if (!response.ok) {
        if (response.status === 404) {
          throw new Error('Blog post not found');
        }
        throw new Error('Failed to fetch blog post');
      }
      const data = await response.json();
      console.log('Blog post data received:', data);
      console.log('Cover image field:', data.coverImage);
      return data;
    },
    enabled: !!slug,
  });

  // Calculate reading time
  useEffect(() => {
    if (post?.content) {
      const wordsPerMinute = 200;
      const wordCount = post.content.replace(/<[^>]*>/g, '').split(/\s+/).length;
      const time = Math.ceil(wordCount / wordsPerMinute);
      setReadingTime(time);
    }
  }, [post?.content]);

  // Increment view count
  const incrementViewMutation = useMutation({
    mutationFn: async () => {
      await apiRequest('POST', `/api/blog/${slug}/view`);
    },
  });

  useEffect(() => {
    if (post && !incrementViewMutation.isSuccess) {
      incrementViewMutation.mutate();
    }
  }, [post]);

  // Bookmark functionality
  const bookmarkMutation = useMutation({
    mutationFn: async () => {
      const method = isBookmarked ? 'DELETE' : 'POST';
      await apiRequest(method, `/api/blog/${slug}/bookmark`);
    },
    onSuccess: () => {
      setIsBookmarked(!isBookmarked);
      toast({
        title: isBookmarked ? 'Bookmark removed' : 'Post bookmarked',
        description: isBookmarked ? 'Removed from your reading list' : 'Added to your reading list',
      });
    },
  });

  const copyToClipboard = () => {
    navigator.clipboard.writeText(window.location.href);
    toast({
      title: 'Link copied',
      description: 'Blog post link copied to clipboard',
    });
  };

  const shareOnTwitter = () => {
    const text = `${post?.title} by ${post?.author}`;
    const url = `https://twitter.com/intent/tweet?text=${encodeURIComponent(text)}&url=${encodeURIComponent(window.location.href)}`;
    window.open(url, '_blank');
  };

  const shareOnFacebook = () => {
    const url = `https://www.facebook.com/sharer/sharer.php?u=${encodeURIComponent(window.location.href)}`;
    window.open(url, '_blank');
  };

  const shareOnLinkedIn = () => {
    const url = `https://www.linkedin.com/sharing/share-offsite/?url=${encodeURIComponent(window.location.href)}`;
    window.open(url, '_blank');
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-gray-600">Loading article...</p>
        </div>
      </div>
    );
  }

  if (error || !post) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center max-w-md mx-auto">
          <h1 className="text-2xl font-bold text-gray-900 mb-4">Article Not Found</h1>
          <p className="text-gray-600 mb-6">
            The article you're looking for doesn't exist or has been removed.
          </p>
          <Button onClick={() => navigate('/')}>
            <ArrowLeft className="h-4 w-4 mr-2" />
            Back to Home
          </Button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-white">
      {/* Navigation Bar */}
      <nav className="sticky top-0 z-50 bg-white border-b border-gray-200">
        <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-16">
            <Button
              variant="ghost"
              onClick={() => navigate('/')}
              className="flex items-center"
            >
              <ArrowLeft className="h-4 w-4 mr-2" />
              Back
            </Button>

            <div className="flex items-center space-x-4">
              {user && (
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => bookmarkMutation.mutate()}
                  disabled={bookmarkMutation.isPending}
                >
                  <Bookmark className={`h-4 w-4 ${isBookmarked ? 'fill-current' : ''}`} />
                </Button>
              )}

              <div className="flex items-center space-x-1">
                <Button variant="ghost" size="sm" onClick={shareOnTwitter}>
                  <Twitter className="h-4 w-4" />
                </Button>
                <Button variant="ghost" size="sm" onClick={shareOnFacebook}>
                  <Facebook className="h-4 w-4" />
                </Button>
                <Button variant="ghost" size="sm" onClick={shareOnLinkedIn}>
                  <Linkedin className="h-4 w-4" />
                </Button>
                <Button variant="ghost" size="sm" onClick={copyToClipboard}>
                  <LinkIcon className="h-4 w-4" />
                </Button>
              </div>
            </div>
          </div>
        </div>
      </nav>

      {/* Article Content */}
      <article className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Header */}
        <header className="mb-8">
          {/* Category & Tags */}
          {post.tags && post.tags.length > 0 && (
            <div className="flex flex-wrap gap-2 mb-4">
              {post.tags.map((tag: string, index: number) => (
                <Badge key={index} variant="secondary" className="text-xs">
                  {tag}
                </Badge>
              ))}
            </div>
          )}

          {/* Title */}
          <h1 className="text-4xl lg:text-5xl font-bold text-gray-900 leading-tight mb-6">
            {post.title}
          </h1>

          {/* Excerpt */}
          {post.excerpt && (
            <p className="text-xl text-gray-600 leading-relaxed mb-8">
              {post.excerpt}
            </p>
          )}

          {/* Cover Image */}
          {post.coverImage && (
            <div className="mb-8">
              <img
                src={post.coverImage}
                alt={post.title}
                className="w-full rounded-lg shadow-lg"
                onError={(e) => {
                  console.error('Cover image failed to load:', post.coverImage);
                  e.currentTarget.style.display = 'none';
                }}
                onLoad={() => {
                  console.log('Cover image loaded successfully:', post.coverImage);
                }}
              />
            </div>
          )}

          {/* Meta Information */}
          <div className="flex items-center justify-between py-4 border-t border-b border-gray-200">
            <div className="flex items-center space-x-6">
              <div className="flex items-center space-x-2">
                <div className="w-10 h-10 bg-blue-600 rounded-full flex items-center justify-center">
                  <User className="h-5 w-5 text-white" />
                </div>
                <div>
                  <p className="font-medium text-gray-900">{post.author}</p>
                  {post.authorEmail && (
                    <p className="text-sm text-gray-500">{post.authorEmail}</p>
                  )}
                </div>
              </div>

              <div className="flex items-center space-x-4 text-sm text-gray-500">
                <div className="flex items-center">
                  <Calendar className="h-4 w-4 mr-1" />
                  <span>{format(new Date(post.publishedAt || post.createdAt), 'MMM dd, yyyy')}</span>
                </div>
                <div className="flex items-center">
                  <Clock className="h-4 w-4 mr-1" />
                  <span>{readingTime} min read</span>
                </div>
                <div className="flex items-center">
                  <Eye className="h-4 w-4 mr-1" />
                  <span>{post.viewCount || 0} views</span>
                </div>
              </div>
            </div>
          </div>
        </header>

        {/* Article Body */}
        <div 
          className="prose prose-lg max-w-none prose-headings:text-gray-900 prose-p:text-gray-800 prose-p:leading-relaxed prose-a:text-blue-600 prose-a:no-underline hover:prose-a:underline prose-strong:text-gray-900 prose-blockquote:border-blue-600 prose-blockquote:bg-blue-50 prose-blockquote:italic prose-code:bg-gray-100 prose-code:px-1 prose-code:py-0.5 prose-code:rounded prose-pre:bg-gray-900 prose-img:rounded-lg prose-img:shadow-lg"
          dangerouslySetInnerHTML={{ __html: post.content }}
        />

        {/* Footer */}
        <footer className="mt-12 pt-8 border-t border-gray-200">
          <div className="flex items-center justify-between">
            <div className="flex items-center space-x-4">
              <div className="flex items-center space-x-2">
                <div className="w-12 h-12 bg-blue-600 rounded-full flex items-center justify-center">
                  <User className="h-6 w-6 text-white" />
                </div>
                <div>
                  <p className="font-medium text-gray-900">{post.author}</p>
                  <p className="text-sm text-gray-500">Author</p>
                </div>
              </div>
            </div>

            <div className="flex items-center space-x-2">
              <Button variant="outline" size="sm" onClick={shareOnTwitter}>
                <Twitter className="h-4 w-4 mr-2" />
                Share
              </Button>
              {user && (
                <Button
                  variant={isBookmarked ? 'default' : 'outline'}
                  size="sm"
                  onClick={() => bookmarkMutation.mutate()}
                  disabled={bookmarkMutation.isPending}
                >
                  <Bookmark className="h-4 w-4 mr-2" />
                  {isBookmarked ? 'Saved' : 'Save'}
                </Button>
              )}
            </div>
          </div>
        </footer>
      </article>
    </div>
  );
}

client/src/pages/category-page.tsx.content:
import { useState } from "react";
import { useRoute } from "wouter";
import { useQuery } from "@tanstack/react-query";
import { ArrowLeft, Search, Play, Clock, Users, BarChart3, Calendar, TrendingUp, Filter } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Link, useLocation } from "wouter";
import { VideoWithCategory } from "@shared/schema";
import { VideoCompletionBadge } from "@/components/video-completion-badge";

export function CategoryPage() {
  const [, params] = useRoute("/category/:slug");
  const slug = params?.slug;
  const [searchQuery, setSearchQuery] = useState("");
  const [sortBy, setSortBy] = useState("alphabetical");
  const [, setLocation] = useLocation();

  // Fetch category details
  const { data: category, isLoading: categoryLoading } = useQuery({
    queryKey: ["/api/categories", slug],
    queryFn: async () => {
      if (!slug) return null;
      const response = await fetch(`/api/categories/${slug}`, {
        credentials: "include",
      });
      if (!response.ok) {
        if (response.status === 404) return null;
        throw new Error("Failed to fetch category");
      }
      return response.json();
    },
    enabled: !!slug,
  });

  // Fetch videos for this category
  const { data: videos = [], isLoading: videosLoading } = useQuery({
    queryKey: ["/api/videos", { categoryId: category?.id }],
    queryFn: async () => {
      if (!category?.id) return [];
      const response = await fetch(`/api/videos?categoryId=${category.id}`, {
        credentials: "include",
      });
      if (!response.ok) throw new Error("Failed to fetch videos");
      return response.json();
    },
    enabled: !!category?.id,
  });

  // Fetch category progress
  const { data: progress } = useQuery({
    queryKey: ["/api/categories", category?.id, "progress"],
    queryFn: async () => {
      if (!category?.id) return null;
      const response = await fetch(`/api/categories/${category.id}/progress`, {
        credentials: "include",
      });
      if (!response.ok) return null;
      return response.json();
    },
    enabled: !!category?.id,
  });

  const filteredVideos = videos.filter((video: VideoWithCategory) => {
    if (!searchQuery) return true;
    return (
      video.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
      video.description?.toLowerCase().includes(searchQuery.toLowerCase())
    );
  });

  // Sort videos based on selected option
  const sortedVideos = [...filteredVideos].sort((a, b) => {
    switch (sortBy) {
      case "newest":
        return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
      case "oldest":
        return new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();
      case "popular":
        return (b.views || 0) - (a.views || 0);
      case "alphabetical":
        return a.title.localeCompare(b.title);
      default:
        return 0;
    }
  });

  // Get featured video (first video or most recent)
  const featuredVideo = sortedVideos[0];

  const handleVideoClick = (video: VideoWithCategory) => {
    setLocation(`/video/${video.id}`);
