              <div className="flex flex-wrap gap-6 mb-8">
                {category.mentorName && (
                  <div className="flex items-center space-x-2 text-white/90">
                    <Users className="h-5 w-5" />
                    <span className="font-medium">Instructor: {category.mentorName}</span>
                  </div>
