import { useState, useEffect } from "react";
import { useParams, useLocation } from "wouter";
import { useMutation, useQuery } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { useToast } from "@/hooks/use-toast";
import { apiRequest } from "@/lib/queryClient";
import { Loader2, CheckCircle } from "lucide-react";

const acceptInvitationSchema = z.object({
  username: z.string().min(3, "Username must be at least 3 characters"),
  fullName: z.string().min(2, "Full name must be at least 2 characters"),
  password: z.string().min(6, "Password must be at least 6 characters"),
  confirmPassword: z.string(),
}).refine((data) => data.password === data.confirmPassword, {
  message: "Passwords don't match",
  path: ["confirmPassword"],
});

type AcceptInvitationData = z.infer<typeof acceptInvitationSchema>;

export default function InvitationPage() {
  const { token } = useParams<{ token: string }>();
  const [, setLocation] = useLocation();
  const { toast } = useToast();
  const [isAccepted, setIsAccepted] = useState(false);

  const { data: invitation, isLoading, error } = useQuery({
    queryKey: ["/api/invitation", token],
    queryFn: async () => {
      const res = await fetch(`/api/invitation/${token}`, { credentials: "include" });
      if (!res.ok) throw new Error("Failed to fetch invitation");
      return res.json();
    },
    enabled: !!token,
  });

  const form = useForm<AcceptInvitationData>({
    resolver: zodResolver(acceptInvitationSchema),
    defaultValues: {
      username: "",
      fullName: "",
      password: "",
      confirmPassword: "",
    },
  });

  const acceptInvitationMutation = useMutation({
    mutationFn: async (data: Omit<AcceptInvitationData, "confirmPassword">) => {
      return await apiRequest("POST", `/api/invitation/${token}/accept`, data);
    },
    onSuccess: () => {
      setIsAccepted(true);
      toast({
        title: "Account created successfully",
        description: "You can now log in with your credentials.",
      });
      setTimeout(() => {
        setLocation("/auth");
      }, 3000);
    },
    onError: (error: Error) => {
      toast({
        title: "Error",
        description: error.message || "Failed to accept invitation",
        variant: "destructive",
      });
    },
  });

  const onSubmit = (data: AcceptInvitationData) => {
    const { confirmPassword, ...submitData } = data;
    acceptInvitationMutation.mutate(submitData);
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <Card className="w-full max-w-md">
          <CardContent className="pt-6">
            <div className="flex items-center justify-center space-x-2">
              <Loader2 className="h-5 w-5 animate-spin" />
              <span>Loading invitation...</span>
            </div>
          </CardContent>
        </Card>
      </div>
    );
  }

  if (error || !invitation) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <Card className="w-full max-w-md">
          <CardHeader className="text-center">
            <CardTitle className="text-red-600">Invalid Invitation</CardTitle>
            <CardDescription>
              This invitation link is invalid or has expired.
            </CardDescription>
          </CardHeader>
          <CardContent>
            <Button
              onClick={() => setLocation("/auth")}
              className="w-full"
            >
              Go to Login
            </Button>
          </CardContent>
        </Card>
      </div>
    );
  }

  if (isAccepted) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <Card className="w-full max-w-md">
          <CardHeader className="text-center">
            <div className="flex justify-center mb-4">
              <CheckCircle className="h-16 w-16 text-green-600" />
            </div>
            <CardTitle className="text-green-600">Account Created!</CardTitle>
            <CardDescription>
              Your account has been created successfully. Redirecting to login...
            </CardDescription>
          </CardHeader>
        </Card>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-50 p-4">
      <Card className="w-full max-w-md">
        <CardHeader className="text-center">
          <CardTitle>Complete Your Registration</CardTitle>
          <CardDescription>
            You've been invited to join Zmartclass as a <strong>{invitation.role}</strong>.
            <br />
            Email: <strong>{invitation.email}</strong>
          </CardDescription>
        </CardHeader>
        <CardContent>
          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
              <FormField
                control={form.control}
                name="username"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Username</FormLabel>
                    <FormControl>
                      <Input placeholder="Enter your username" {...field} />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control}
                name="fullName"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Full Name</FormLabel>
                    <FormControl>
                      <Input placeholder="Enter your full name" {...field} />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control}
                name="password"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Password</FormLabel>
                    <FormControl>
                      <Input
                        type="password"
                        placeholder="Enter your password"
                        {...field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <FormField
                control={form.control}
                name="confirmPassword"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Confirm Password</FormLabel>
                    <FormControl>
                      <Input
                        type="password"
                        placeholder="Confirm your password"
                        {...field}
                      />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              <Button
                type="submit"
                className="w-full"
                disabled={acceptInvitationMutation.isPending}
              >
                {acceptInvitationMutation.isPending ? (
                  <>
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    Creating Account...
                  </>
                ) : (
                  "Create Account"
                )}
              </Button>
            </form>
          </Form>
        </CardContent>
      </Card>
    </div>
  );
}

client/src/pages/landing-page.tsx.content:
import { useState } from "react";
import EventApplicationModal from '@/components/event-application-modal';
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Badge } from "@/components/ui/badge";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Textarea } from "@/components/ui/textarea";
import { useToast } from "@/hooks/use-toast";
import { useMutation, useQuery } from "@tanstack/react-query";
import { useAuth } from "@/hooks/use-auth";
import { useLocation } from "wouter";
import { 
  Play, 
  Users, 
  BookOpen, 
  Trophy, 
  Star, 
  CheckCircle,
  ArrowRight,
  Video,
  GraduationCap,
  Target,
  Zap,
  Clock,
  Award,
  Mail,
  Eye,
  Calendar,
  Newspaper
} from "lucide-react";
import { apiRequest } from "@/lib/queryClient";

const loginSchema = z.object({
  username: z.string().email("Please enter a valid email"),
  password: z.string().min(1, "Password is required"),
});

const contactSchema = z.object({
  name: z.string().min(1, "Name is required"),
  email: z.string().min(1, "Email is required").email("Invalid email address"),
  message: z.string().min(1, "Message is required"),
});

type LoginForm = z.infer<typeof loginSchema>;
type ContactForm = z.infer<typeof contactSchema>;

export function LandingPage() {
  const { toast } = useToast();
  const { user } = useAuth();
  const [, navigate] = useLocation();
  const [isLoading, setIsLoading] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [applicationModalOpen, setApplicationModalOpen] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<any>(null);
  const [activeTab, setActiveTab] = useState("events");

  // Fetch app settings for dynamic content
  const { data: settings } = useQuery({
    queryKey: ["/api/settings"],
  });

  // Fetch categories for course showcase
  const { data: categories } = useQuery({
    queryKey: ["/api/categories"],
  });

  // Fetch some featured videos
  const { data: featuredVideos } = useQuery({
    queryKey: ["/api/videos"],
  });

  // Fetch active events for landing page display
  const { data: events = [] } = useQuery({
    queryKey: ["/api/events", "public"],
    queryFn: () => fetch("/api/events?public=true&status=active").then(res => res.json()),
  });

  // Fetch blog posts for news section
  const { data: blogPosts = [] } = useQuery({
    queryKey: ["/api/blog", "published"],
    queryFn: () => fetch("/api/blog?status=published&public=true").then(res => res.json()),
  });

  const form = useForm<LoginForm>({
    resolver: zodResolver(loginSchema),
    defaultValues: {
      username: "",
      password: "",
    },
  });

  const contactForm = useForm<ContactForm>({
    resolver: zodResolver(contactSchema),
    defaultValues: {
      name: "",
      email: "",
      message: "",
    },
  });

  const loginMutation = useMutation({
    mutationFn: async (data: LoginForm) => {
      const response = await apiRequest("POST", "/api/login", {
        email: data.username,
        password: data.password
      });
      return response.json();
    },
    onSuccess: (data) => {
      // Refetch user data to update auth state
      window.location.href = "/home";
    },
    onError: (error: any) => {
      toast({
        title: "Login failed",
        description: error.message || "Invalid credentials",
        variant: "destructive",
      });
    },
  });

  const contactMutation = useMutation({
    mutationFn: async (data: ContactForm) => {
      const response = await apiRequest("POST", "/api/contact", data);
      return response.json();
    },
    onSuccess: () => {
      toast({
        title: "Message sent successfully!",
        description: "We'll get back to you soon.",
      });
      contactForm.reset();
    },
    onError: (error: any) => {
      toast({
        title: "Failed to send message",
        description: error.message || "Please try again later.",
        variant: "destructive",
      });
    },
  });

  const onSubmit = (data: LoginForm) => {
    setIsLoading(true);
    loginMutation.mutate(data);
    setIsLoading(false);
  };

  const onContactSubmit = (data: ContactForm) => {
    contactMutation.mutate(data);
  };

  // If user is already logged in, redirect to home
  if (user) {
    navigate("/home");
    return null;
  }

  const stats = [
    { icon: Users, label: settings?.stat1Label || "Active Students", value: settings?.stat1Value || "10,000+", color: "text-blue-600" },
    { icon: BookOpen, label: settings?.stat2Label || "Courses", value: settings?.stat2Value || categories?.length || "50+", color: "text-green-600" },
    { icon: Video, label: settings?.stat3Label || "Video Lessons", value: settings?.stat3Value || featuredVideos?.length || "500+", color: "text-purple-600" },
    { icon: Trophy, label: settings?.stat4Label || "Success Rate", value: settings?.stat4Value || "95%", color: "text-orange-600" },
  ];

  const features = [
    {
      icon: GraduationCap,
      title: settings?.feature1Title || "Expert-Led Courses",
      description: settings?.feature1Description || "Learn from industry professionals with real-world experience",
    },
    {
      icon: Target,
      title: settings?.feature2Title || "Practical Learning",
      description: settings?.feature2Description || "Hands-on projects and real case studies to build your portfolio",
    },
    {
      icon: Zap,
      title: settings?.feature3Title || "Fast-Track Progress",
      description: settings?.feature3Description || "Accelerated learning paths designed for busy professionals",
    },
    {
      icon: Clock,
      title: "Flexible Schedule",
      description: "Learn at your own pace with lifetime access to content",
    },
    {
      icon: Award,
      title: "Certification",
      description: "Earn recognized certificates upon course completion",
    },
    {
      icon: Users,
      title: "Community Support",
      description: "Join a thriving community of learners and mentors",
    },
  ];

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 via-white to-purple-50">
      {/* Navigation Bar */}
      <nav className="bg-white shadow-lg sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-16">
            {/* Logo */}
            <div className="flex items-center">
              <div className="flex flex-col leading-tight">
                <div className="text-xl sm:text-2xl font-bold text-blue-600">Zmartclass</div>
                <div className="text-xs sm:text-sm text-gray-500 font-normal -mt-1 text-right">De mentee</div>
              </div>
            </div>

            {/* Navigation Links */}
            <div className="hidden md:flex items-center space-x-8">
              <a href="#about" className="text-gray-700 hover:text-blue-600 font-medium">About Us</a>
              <a href="#programs" className="text-gray-700 hover:text-blue-600 font-medium">Our Programs</a>
